export const arkade_kitties = "// ArkadeKitties - Simplified Breeding Contract\n// Demonstrates commit-reveal breeding with oracle randomness\n//\n// Key features demonstrated:\n// - group.isFresh: Detect newly minted kitties\n// - group.control: Verify species membership\n// - group.metadataHash: Verify genome/attributes\n// - group.delta: Detect minting vs transfer\n//\n// Asset hierarchy:\n// - speciesControlId: The \"species\" control asset (e.g., \"ArkadeKitties\")\n// - Each kitty is a unique asset controlled by speciesControlId\n// - Breeding creates a new kitty with isFresh=1\n\noptions {\n    server = server;\n    exit = 576;  // ~4 days for breeding timeout\n}\n\ncontract ArkadeKitties(\n    bytes32 speciesControlId,\n    pubkey oraclePk\n) {\n    // Breed two kitties to create a new one\n    // Parents must be species-controlled, child must be fresh\n    function breed(\n        bytes32 sireId,\n        bytes32 dameId,\n        bytes32 childId,\n        bytes32 sireGenomeHash,\n        bytes32 dameGenomeHash,\n        bytes32 expectedChildMetadataHash,\n        signature oracleSig,\n        int childOutputIdx,\n        int sireOutputIdx,\n        int dameOutputIdx,\n        int ctrlOutputIdx\n    ) {\n        // Verify sire is species-controlled with correct genome\n        let sireGroup = tx.assetGroups.find(sireId);\n        require(sireGroup.control == speciesControlId, \"sire not species-controlled\");\n        require(sireGroup.metadataHash == sireGenomeHash, \"sire genome mismatch\");\n        require(sireGroup.delta == 0, \"sire must be retained\");\n\n        // Verify dame is species-controlled with correct genome\n        let dameGroup = tx.assetGroups.find(dameId);\n        require(dameGroup.control == speciesControlId, \"dame not species-controlled\");\n        require(dameGroup.metadataHash == dameGenomeHash, \"dame genome mismatch\");\n        require(dameGroup.delta == 0, \"dame must be retained\");\n\n        // Verify child is fresh (new issuance in this tx)\n        let childGroup = tx.assetGroups.find(childId);\n        require(childGroup.isFresh == 1, \"child must be fresh\");\n        require(childGroup.delta == 1, \"must mint exactly 1 child\");\n        require(childGroup.control == speciesControlId, \"child not species-controlled\");\n        require(childGroup.metadataHash == expectedChildMetadataHash, \"child genome mismatch\");\n\n        // Species control must be retained (delta == 0)\n        let ctrlGroup = tx.assetGroups.find(speciesControlId);\n        require(ctrlGroup.delta == 0, \"species control must be retained\");\n\n        // Oracle signature validates the breeding (genome combination)\n        require(checkSig(oracleSig, oraclePk), \"invalid oracle sig\");\n\n        // Verify outputs contain all assets\n        require(tx.outputs[childOutputIdx].assets.lookup(childId) == 1, \"child not in output\");\n        require(tx.outputs[sireOutputIdx].assets.lookup(sireId) == 1, \"sire not returned\");\n        require(tx.outputs[dameOutputIdx].assets.lookup(dameId) == 1, \"dame not returned\");\n        require(tx.outputs[ctrlOutputIdx].assets.lookup(speciesControlId) == 1, \"ctrl not retained\");\n    }\n\n    // Transfer a kitty to a new owner\n    function transfer(bytes32 kittyId, pubkey newOwnerPk, signature ownerSig, pubkey ownerPk) {\n        let kittyGroup = tx.assetGroups.find(kittyId);\n\n        // Must be existing kitty (not fresh)\n        require(kittyGroup.isFresh == 0, \"must be existing kitty\");\n\n        // Must be species-controlled\n        require(kittyGroup.control == speciesControlId, \"not species-controlled\");\n\n        // Must be transfer (delta == 0)\n        require(kittyGroup.delta == 0, \"must be transfer only\");\n\n        require(tx.outputs[0].assets.lookup(kittyId) == 1, \"kitty not in output\");\n        require(tx.outputs[0].scriptPubKey == new SingleSig(newOwnerPk), \"wrong destination\");\n        require(checkSig(ownerSig, ownerPk), \"invalid owner sig\");\n    }\n}\n";

export const bond_mint = "// BondMint Contract\n//\n// Per-issuance collateral vault holding the borrower's debit tokens. Created\n// atomically by RepaymentPool.issue. Each vault represents one issuance of\n// `mintedAmount` credit + `mintedAmount` debit (1:1) by a borrower against\n// `collateral` sats, maturing at block height `maturity`.\n//\n// SETTLEMENT PATHS (four; all burn the vault's debit exactly)\n//   repay      — pre-maturity, borrower-signed. The borrower pays par USDT,\n//                takes their collateral back.\n//   liquidate  — pre-maturity MARGIN CALL, permissionless. Triggered when\n//                `collateralValue < liqThresholdBps × mintedAmount / 10000`\n//                at the pool. Oracle-priced sale; collateral → auctioneer;\n//                USDT → pool. This is what keeps every vault in the pool\n//                covenant-thresholded healthy at every block — the invariant\n//                that makes credit tokens genuinely fungible.\n//   auction    — post-maturity DEFAULT, permissionless, in the auction window.\n//                Same oracle-priced sale.\n//   roll       — pre-maturity, borrower-signed. Authorises migration of this\n//                vault to a NEXT-maturity pool in a single atomic tx (paired\n//                with RepaymentPool.rollOut on this pool and rollIn on the\n//                new pool, plus a non_interactive_swap fill that bridges the\n//                USDT discharge). See docs/bonds.md §Loan roll.\n//\n// PHASED TIMELINE\n//   [-, maturity)                              REPAY phase    vault.repay,\n//                                                             vault.liquidate,\n//                                                             vault.roll\n//   [maturity, maturity + auctionWindow)        AUCTION phase  vault.auction\n//   [maturity + auctionWindow, +)               REDEEM phase   no vault function\n//\n// PERMISSIONLESS SETTLEMENT\n//   Each settlement-side function's debit-burn check is STRICT equality\n//   (`sumInputs == sumOutputs + mintedAmount`), so an attacker cannot batch\n//   multiple vault inputs into one settlement tx: each vault's individual\n//   check requires the global debit delta to equal THAT vault's mintedAmount\n//   exactly, which fails closed for any multi-vault combination. The pool\n//   side enforces the same strict equality symmetrically.\n//\n//   Within the pre-maturity phase, the right pairing is enforced by a\n//   combination of per-function output-pin conflicts AND pool-side borrower\n//   signatures on every state-transition pool function:\n//     - vault.repay         pins output[1]=borrower; pool.acceptRepayment\n//                           pins output[1]=borrower (same dest, no conflict)\n//                           — and borrower-signs the spend so non-consensual\n//                           pairings are blocked.\n//     - vault.liquidate     pins output[1]=auctioneer; pool.liquidate pins\n//                           output[1]=auctioneer (same dest, no conflict)\n//                           — pool side health-gates via oracle, so a\n//                           healthy vault cannot be liquidated.\n//     - vault.roll          pins NO output (it just authorises the spend);\n//                           the paired pool.rollOut REQUIRES the borrower's\n//                           signature too. Without the pool-side sig, an\n//                           attacker could pair the permissionless\n//                           vault.liquidate with rollOut and force-liquidate\n//                           a healthy vault at par. rollOut's sig blocks\n//                           that pairing.\n//\n//   Auctioneer identity is a witness pubkey; they pin their own collateral\n//   destination by signing the tx they construct.\n//\n// POOL-AUTHENTICATION CAVEAT\n//   The \"genuine pool not co-spent\" check verifies only that an input holds\n//   the debit-control asset (`tx.inputs[poolIdx].assets.lookup(debitCtrlId)\n//   >= 1`), not that the input's scriptPubKey is the canonical RepaymentPool\n//   covenant. Safety therefore rests on the asset-registry invariant that\n//   no pool function ever lets debitCtrlId leak from its output[0]. EVERY\n//   future pool function MUST retain debitCtrlId. The regression test\n//   `test_pool_retains_debit_ctrl_in_every_function` enforces this at the\n//   ASM level — do not delete it.\n//\n// UNILATERAL EXIT (Arkade operator offline, after `<exit>` blocks)\n//   Exit signers come from the function's pubkey parameters. In practice the\n//   borrower is the only relevant signer for unilateral collateral recovery.\n//   See docs/bonds.md §\"Unilateral exits\".\n\nimport \"single_sig.ark\";\n\noptions {\n  server = server;\n  exit = exit;\n}\n\ncontract BondMint(\n  pubkey  borrowerPk,\n  bytes32 debitAssetId,\n  bytes32 debitCtrlId,\n  int     mintedAmount,\n  int     collateral,\n  int     maturity,\n  int     auctionWindow,\n  int     exit\n) {\n\n  // REPAY — pre-maturity, atomic with RepaymentPool.acceptRepayment.\n  //   output[0]: pool re-created (enforced by acceptRepayment)\n  //   output[1]: collateral sats → borrower\n  function repay(signature borrowerSig, int poolIdx) {\n    require(checkSig(borrowerSig, borrowerPk), \"invalid borrower sig\");\n    require(tx.time < maturity, \"loan matured\");\n\n    require(tx.inputs[poolIdx].assets.lookup(debitCtrlId) >= 1, \"genuine pool not co-spent\");\n\n    let debitGroup = tx.assetGroups.find(debitAssetId);\n    require(debitGroup.sumInputs == debitGroup.sumOutputs + mintedAmount, \"debit not burned exactly mintedAmount\");\n\n    require(tx.outputs[1].value >= collateral, \"collateral not returned\");\n    require(tx.outputs[1].scriptPubKey == new SingleSig(borrowerPk), \"output 1 not borrower\");\n  }\n\n  // LIQUIDATE — pre-maturity MARGIN CALL, permissionless. The pool's liquidate\n  // does the oracle + threshold + payout math; this script authorises the\n  // spend (time gate + pool co-spent + debit burn) and pins the collateral\n  // output to the auctioneer.\n  //   output[0]: pool re-created (enforced by acceptAuction-style pool.liquidate)\n  //   output[1]: collateral (or sold portion) → auctioneer\n  //\n  // DEFENSE-IN-DEPTH: output[1].value > 0 ensures *something* flows to the\n  // auctioneer-pinned output. The exact value (collateralSold or all\n  // collateral, depending on over-cover/shortfall) is enforced by the\n  // co-spent pool.liquidate. If that pool-side check ever regresses, this\n  // vault-side floor still prevents the \"1 sat to auctioneer, rest as miner\n  // fee\" siphon shape.\n  function liquidate(int poolIdx, pubkey auctioneerPk) {\n    require(tx.time < maturity, \"matured; use auction\");\n\n    require(tx.inputs[poolIdx].assets.lookup(debitCtrlId) >= 1, \"genuine pool not co-spent\");\n\n    let debitGroup = tx.assetGroups.find(debitAssetId);\n    require(debitGroup.sumInputs == debitGroup.sumOutputs + mintedAmount, \"debit not burned exactly mintedAmount\");\n\n    require(tx.outputs[1].value > 0, \"auctioneer output empty\");\n    require(tx.outputs[1].scriptPubKey == new SingleSig(auctioneerPk), \"output 1 not auctioneer\");\n  }\n\n  // AUCTION — during the auction window, atomic with RepaymentPool.acceptAuction.\n  // Permissionless: any auctioneer constructs the tx and specifies their own\n  // collateral destination via `auctioneerPk`.\n  //   output[0]: pool re-created (enforced by acceptAuction)\n  //   output[1]: collateral (or sold portion) → auctioneer\n  function auction(int poolIdx, pubkey auctioneerPk) {\n    require(tx.time >= maturity, \"not yet matured\");\n    int windowEnd = maturity + auctionWindow;\n    require(tx.time < windowEnd, \"auction window closed\");\n\n    require(tx.inputs[poolIdx].assets.lookup(debitCtrlId) >= 1, \"genuine pool not co-spent\");\n\n    let debitGroup = tx.assetGroups.find(debitAssetId);\n    require(debitGroup.sumInputs == debitGroup.sumOutputs + mintedAmount, \"debit not burned exactly mintedAmount\");\n\n    require(tx.outputs[1].value > 0, \"auctioneer output empty\");\n    require(tx.outputs[1].scriptPubKey == new SingleSig(auctioneerPk), \"output 1 not auctioneer\");\n  }\n\n  // ROLL — borrower-signed authorisation to migrate this vault to a next-\n  // maturity pool. Pre-maturity, atomic with RepaymentPool.rollOut on the\n  // OLD pool (this vault's pool) and RepaymentPool.rollIn on the NEW pool.\n  // The borrower's signature is the consent gate; the old pool's rollOut\n  // enforces that the obligation is discharged (USDT inflow ≥ mintedAmount);\n  // the new pool's rollIn enforces that the new vault is properly\n  // collateralised. This script just authorises the spend and burns the\n  // old debit. The collateral input is released into the tx — the paired\n  // rollIn must claim it into a new BondMint output, or the tx fails closed.\n  //\n  //   output[0..]: free (rollOut + rollIn + swap pin their own outputs at\n  //                witness-supplied indices)\n  function roll(signature borrowerSig, int poolIdx) {\n    require(checkSig(borrowerSig, borrowerPk), \"invalid borrower sig\");\n    require(tx.time < maturity, \"vault matured\");\n\n    require(tx.inputs[poolIdx].assets.lookup(debitCtrlId) >= 1, \"genuine pool not co-spent\");\n\n    let debitGroup = tx.assetGroups.find(debitAssetId);\n    require(debitGroup.sumInputs == debitGroup.sumOutputs + mintedAmount, \"debit not burned exactly mintedAmount\");\n  }\n}\n";

export const repayment_pool = "// RepaymentPool Contract\n//\n// Per-maturity singleton implementing a fixed-maturity bond market: borrowers\n// self-issue credit + debit tokens (1:1) against collateral; the credit half\n// is sold by the borrower for USDT on the order book (via non_interactive_swap)\n// — that is the borrower's loan and the lender's entry point. NO interest rate;\n// the yield is whatever discount the market sets at sale time.\n//\n// Two settlement paths close a vault outside of voluntary repayment:\n//\n//   MARGIN CALL (pre-maturity, permissionless)\n//     `liquidate` fires the moment `collateralValue < liqThresholdBps ×\n//     mintedAmount / 10000`. The vault's collateral is sold at the oracle\n//     price, USDT enters the pool, the obligation is extinguished. This keeps\n//     every vault in the pool thresholded healthy at every block, which is\n//     what preserves credit-token fungibility on the order book: a lender\n//     buying credit doesn't need to know WHICH vault backs it because every\n//     vault in the pool is covenant-guaranteed to be above the health floor.\n//\n//   AUCTION (post-maturity default, permissionless)\n//     `acceptAuction` closes vaults whose borrowers did not repay by maturity.\n//     Same oracle-priced sale, same auctioneer-discount incentive. Only fires\n//     in the dedicated auction window so it can't race with redemptions.\n//\n// PHASED TIMELINE\n//   [-, maturity)                              REPAY    issue, acceptRepayment,\n//                                                       rollOut, rollIn,\n//                                                       liquidate (margin call)\n//   [maturity, maturity + auctionWindow)        AUCTION  acceptAuction only\n//   [maturity + auctionWindow, +)               REDEEM   redeem only\n//\n// (Pre-maturity functions are mutually safe by THREE layers:\n//   1. STRICT debit-burn equality on every settlement function — `sumInputs\n//      == sumOutputs + N` (never `>=`) — so multi-vault batching fails\n//      closed before any output-pin phase can be reached. The credit\n//      asset is also constrained on every settlement (delta == 0), so an\n//      adversary cannot co-burn their own credit to dilute remaining\n//      holders.\n//   2. Per-function output-pin conflicts on output[1]: acceptRepayment\n//      pins borrower, liquidate pins auctioneer — incompatible script\n//      pubkeys for the same output index, so the wrong vault function\n//      cannot pair with the wrong pool function.\n//   3. Pool-side borrower signature on every state-mutating user-driven\n//      function: issue, rollOut, rollIn, redeem (and acceptRepayment via\n//      the vault-side BondMint.repay sig). The two settlement functions\n//      that are intentionally permissionless (liquidate, acceptAuction)\n//      gate on the oracle witness + a hard health/time check. rollOut\n//      could NOT be permissionless because vault.liquidate is — pairing\n//      them would let an attacker force-liquidate healthy vaults at par.\n//  acceptAuction and redeem are also mutually time-exclusive with each\n//  other and with the pre-maturity functions, so vault.auction binds\n//  settlement to acceptAuction by time.)\n//\n// LOAN ROLL — single-tx atomic\n//   A borrower migrates their position to the next maturity in one tx using\n//   three new functions: BondMint.roll (consent + old debit burn), this\n//   pool's rollOut (validate old vault, take USDT discharge), and the NEW\n//   pool's rollIn (oracle-priced new issuance + collateral migration). All\n//   three use WITNESS output indices (outIdxPool, outIdxVault, outIdxCredit),\n//   so they compose with a non_interactive_swap fill in the same tx without\n//   the cross-covenant output[0] conflict that would otherwise block atomic\n//   composition. See docs/bonds.md §Loan roll.\n//\n// PERMISSIONLESS AUCTION + LIQUIDATION\n//   Any auctioneer constructs a tx with the oracle witness, providing USDT\n//   and taking the collateral. Incentive: the `auctionDiscountBps` haircut on\n//   pool income is the auctioneer's profit (e.g. 50 bps = 0.5% spread). The\n//   same discount applies to both margin-call liquidations and post-maturity\n//   auctions, so the same keepers/bots service both.\n//\n// REDEEM\n//   Credit holders convert credit → USDT pro-rata after the auction window\n//   closes. Both usdt and credit are fixed at this point, so the rate\n//   `usdtBalance / totalCreditOutstanding` is fair for all redeem orders, no\n//   late-redeemer advantage.\n//\n// UNILATERAL EXIT (Arkade operator offline, after `<exit>` blocks)\n//   - BondMint per-vault: collateral recoverable cooperatively or unilaterally\n//     via N-of-N + CSV; the surviving signer is the borrower\n//     (single-owner-effective on the unilateral path).\n//   - RepaymentPool aggregate: the REDEEM phase drains the pool into\n//     per-holder SingleSig UTXOs — each of those has a clean single-owner\n//     exit, so the lasting on-chain state after every holder redeems is\n//     fully self-sovereign and the pool's aggregate exit surface goes to\n//     zero. See docs/bonds.md §\"Unilateral exits\".\n//\n// STATE carried forward on every spend:\n//   usdtBalance, totalCreditOutstanding, totalDebitOutstanding\n//\n// MONETIZATION\n//   auctionDiscountBps (wired): auctioneer's spread on pool income, paid on\n//   both margin-call liquidations and post-maturity auctions. Origination\n//   fee, redemption fee, and order-book fee are enumerated follow-ups\n//   (M1–M3 in docs/bonds.md).\n\nimport \"bond_mint.ark\";\n\noptions {\n  server = server;\n  exit = exit;\n}\n\ncontract RepaymentPool(\n  bytes32 usdtAssetId,\n  bytes32 creditAssetId,         // fungible per-maturity credit (lender entitlement)\n  bytes32 creditCtrlId,          // control asset gating credit mint\n  bytes32 debitAssetId,          // fungible per-maturity debit (borrower obligation)\n  bytes32 debitCtrlId,           // control asset gating debit mint\n  bytes32 ticker,                // oracle feed id (e.g. sha256(\"BTC/USDT\"))\n  pubkey  oraclePk,              // price oracle (Fuji-style signed feed)\n  int     oracleMaxAgeSeconds,   // max oracle staleness, in SECONDS (tx.offchainTime); contrast with maturity/auctionWindow which are BLOCK HEIGHTS (tx.time)\n  int     initRatioBps,          // required collateral ratio at issuance (e.g. 15000 = 150%)\n  int     liqThresholdBps,       // margin-call trigger: liquidate when collateralValue < this × mintedAmount / 10000 (e.g. 11000 = 110%)\n  int     maturity,              // block height: settlement boundary\n  int     auctionWindow,         // blocks: auction phase length post-maturity\n  int     auctionDiscountBps,    // bps: auctioneer's spread on pool income (0..10000)\n  int     usdtBalance,\n  int     totalCreditOutstanding,\n  int     totalDebitOutstanding,\n  int     exit\n) {\n\n  // ISSUE — pre-maturity, borrower mints `amount` credit + `amount` debit (1:1)\n  // and posts collateral. Credit → borrower's wallet (to sell). Debit → a new\n  // BondMint vault that locks the collateral.\n  //   output[0]: pool re-created (totalCredit + amount, totalDebit + amount)\n  //   output[1]: `amount` credit → borrower\n  //   output[2]: BondMint vault holding collateral + `amount` debit\n  function issue(int amount, int collateral, pubkey borrowerPk, signature borrowerSig, int oraclePrice, int oracleTime, signature oracleSig) {\n    require(amount > 0, \"zero issuance\");\n    require(collateral > 0, \"zero collateral\");\n    // Deployment-safety invariants: collected here at issuance time so a\n    // misconfigured pool can never originate a vault.\n    //  - initRatioBps > liqThresholdBps: a vault minted at the minimum\n    //    collateral must NOT be immediately liquidatable in the same block.\n    //  - liqThresholdBps > 0: a non-positive health threshold would invert\n    //    the liquidate gate (every vault liquidatable, or none).\n    //  - auctionWindow > 0: a zero-length auction window collapses the\n    //    `tx.time >= maturity && tx.time < maturity` gate to an empty set,\n    //    so no defaulted vault can ever be settled via acceptAuction —\n    //    mintedAmount stays in totalDebitOutstanding forever and credit\n    //    holders absorb the full default. Same class of deployment invariant\n    //    as the ratio checks above.\n    //  - auctionDiscountBps ∈ [0, 10000): an out-of-range discount bricks\n    //    every liquidate + acceptAuction (settlement-side runtime check\n    //    fails closed). Validate at deployment so pool issuance fails\n    //    rather than silently producing an unsettleable book.\n    require(initRatioBps > liqThresholdBps, \"liq threshold must be below init ratio\");\n    require(liqThresholdBps > 0, \"liq threshold must be positive\");\n    require(auctionWindow > 0, \"auction window must be positive\");\n    require(auctionDiscountBps >= 0, \"negative discount\");\n    require(auctionDiscountBps < 10000, \"discount >= 100%\");\n    require(tx.time < maturity, \"pool matured\");\n    require(checkSig(borrowerSig, borrowerPk), \"invalid borrower sig\");\n    require(oraclePrice > 0, \"invalid oracle price\");\n\n    int oracleAge = tx.offchainTime - oracleTime;\n    require(oracleAge >= 0, \"future-dated oracle\");\n    require(oracleAge <= oracleMaxAgeSeconds, \"stale oracle\");\n    let oracleMsg = sha256(ticker + oraclePrice + oracleTime);\n    require(checkSigFromStack(oracleSig, oraclePk, oracleMsg), \"invalid oracle signature\");\n\n    // FOLLOW-UP: `collateral * oraclePrice` overflows int64 above ~92 BTC at\n    // a $1M BTC price; OP_MUL64 fails closed. Chunk issuance or rescale the\n    // price denominator (e.g. 1e4 vs 1e8) for very large vaults.\n    int collateralValue = collateral * oraclePrice / 100000000;\n    // Ceiling division on the required collateral floor: floor division\n    // lets dust-sized issuances bypass collateralisation entirely\n    // (`amount=1, initRatioBps=14999` floors to `required=1`, so 1 sat of\n    // collateral mints 1 credit + 1 debit). An attacker could flood the\n    // auction window with thousands of dust defaults that are unprofitable\n    // for auctioneers to settle (gas > profit), leaving them as permanent\n    // deadweight in totalDebitOutstanding. Ceiling rounds UP, so\n    // `1 * 14999 / 10000` → 2, breaking the dust-mint shape.\n    int required = (amount * initRatioBps + 9999) / 10000;\n    require(collateralValue >= required, \"undercollateralized at issuance\");\n\n    let creditGroup = tx.assetGroups.find(creditAssetId);\n    require(creditGroup.delta == amount, \"credit delta mismatch\");\n    require(creditGroup.control == creditCtrlId, \"wrong credit control\");\n    let debitGroup = tx.assetGroups.find(debitAssetId);\n    require(debitGroup.delta == amount, \"debit delta mismatch\");\n    require(debitGroup.control == debitCtrlId, \"wrong debit control\");\n    let ccGroup = tx.assetGroups.find(creditCtrlId);\n    require(ccGroup.delta == 0, \"credit control changed\");\n    let dcGroup = tx.assetGroups.find(debitCtrlId);\n    require(dcGroup.delta == 0, \"debit control changed\");\n\n    int creditNext = totalCreditOutstanding + amount;\n    int debitNext  = totalDebitOutstanding + amount;\n\n    require(\n      tx.outputs[0].scriptPubKey == new RepaymentPool(\n        usdtAssetId, creditAssetId, creditCtrlId, debitAssetId, debitCtrlId, ticker,\n        oraclePk, oracleMaxAgeSeconds, initRatioBps, liqThresholdBps, maturity, auctionWindow, auctionDiscountBps,\n        usdtBalance, creditNext, debitNext, exit\n      ),\n      \"invalid pool recreation\"\n    );\n    require(tx.outputs[0].assets.lookup(usdtAssetId) >= usdtBalance, \"pool usdt short\");\n    require(tx.outputs[0].assets.lookup(creditCtrlId) >= 1, \"credit control not retained\");\n    require(tx.outputs[0].assets.lookup(debitCtrlId) >= 1, \"debit control not retained\");\n\n    require(tx.outputs[1].assets.lookup(creditAssetId) >= amount, \"credit not delivered\");\n    require(tx.outputs[1].scriptPubKey == new SingleSig(borrowerPk), \"credit dest not borrower\");\n\n    require(\n      tx.outputs[2].scriptPubKey == new BondMint(\n        borrowerPk, debitAssetId, debitCtrlId, amount, collateral, maturity, auctionWindow, exit\n      ),\n      \"invalid vault\"\n    );\n    require(tx.outputs[2].value >= collateral, \"collateral not locked\");\n    require(tx.outputs[2].assets.lookup(debitAssetId) >= amount, \"debit not custodied in vault\");\n  }\n\n  // ACCEPT REPAYMENT — pre-maturity, co-spent with BondMint.repay.\n  //   input[vaultIdx]: the BondMint being repaid (validated by reconstruction)\n  //   output[0]: pool re-created (usdt + mintedAmount, totalDebit - mintedAmount)\n  //   output[1]: collateral sats → borrower\n  function acceptRepayment(pubkey borrowerPk, int vaultIdx, int mintedAmount, int collateral) {\n    require(mintedAmount > 0, \"zero amount\");\n    require(mintedAmount <= totalDebitOutstanding, \"exceeds outstanding\");\n    require(tx.time < maturity, \"matured; use acceptAuction\");\n\n    require(\n      tx.inputs[vaultIdx].scriptPubKey == new BondMint(\n        borrowerPk, debitAssetId, debitCtrlId, mintedAmount, collateral, maturity, auctionWindow, exit\n      ),\n      \"vault input mismatch\"\n    );\n\n    let debitGroup = tx.assetGroups.find(debitAssetId);\n    require(debitGroup.sumInputs == debitGroup.sumOutputs + mintedAmount, \"debit not burned exactly mintedAmount\");\n    let creditGroup = tx.assetGroups.find(creditAssetId);\n    require(creditGroup.delta == 0, \"credit must not move on repayment\");\n    let ccGroup = tx.assetGroups.find(creditCtrlId);\n    require(ccGroup.delta == 0, \"credit control changed\");\n    let dcGroup = tx.assetGroups.find(debitCtrlId);\n    require(dcGroup.delta == 0, \"debit control changed\");\n\n    int usdtNext  = usdtBalance + mintedAmount;\n    int debitNext = totalDebitOutstanding - mintedAmount;\n\n    require(\n      tx.outputs[0].scriptPubKey == new RepaymentPool(\n        usdtAssetId, creditAssetId, creditCtrlId, debitAssetId, debitCtrlId, ticker,\n        oraclePk, oracleMaxAgeSeconds, initRatioBps, liqThresholdBps, maturity, auctionWindow, auctionDiscountBps,\n        usdtNext, totalCreditOutstanding, debitNext, exit\n      ),\n      \"invalid pool recreation\"\n    );\n    require(tx.outputs[0].assets.lookup(usdtAssetId) >= usdtNext, \"repayment not received\");\n    require(tx.outputs[0].assets.lookup(creditCtrlId) >= 1, \"credit control not retained\");\n    require(tx.outputs[0].assets.lookup(debitCtrlId) >= 1, \"debit control not retained\");\n\n    require(tx.outputs[1].value >= collateral, \"collateral not returned\");\n    require(tx.outputs[1].scriptPubKey == new SingleSig(borrowerPk), \"collateral dest not borrower\");\n  }\n\n  // ROLL OUT — borrower co-spends their old BondMint to extinguish the\n  // old-maturity obligation. A paired rollIn on a NEXT-maturity pool opens a\n  // new vault using the same collateral atomically (no fronted capital). USDT\n  // discharging the old obligation arrives in the same tx from an order-book\n  // maker (atomically buying the new credit via non_interactive_swap) or, in\n  // a simpler variant, from the borrower's own wallet.\n  //\n  // Variable output indices: every output that rollOut pins is at a witness-\n  // supplied index, so the borrower (or wallet) can place this pool's\n  // recreation wherever the rollIn / swap / new-vault outputs allow. Inputs\n  // are still index-witnessed (vaultIdx) the same way.\n  //\n  // SAFETY — pool-side borrower signature is REQUIRED. The vault-side path\n  // pairs vault.roll (borrower-signed) with rollOut; the vault-side path\n  // also exposes vault.liquidate (PERMISSIONLESS, pre-maturity) — without a\n  // pool-side sig, an attacker could pair vault.liquidate with rollOut and\n  // pay par-USDT to take a healthy vault's full collateral, bypassing\n  // pool.liquidate's health gate. The pool-side sig blocks that pairing.\n  //\n  //   input[vaultIdx]:    the OLD BondMint being closed\n  //   output[outIdxPool]: this pool re-created (usdt += expectedDischarge,\n  //                       totalDebit -= oldMintedAmount, totalCredit unchanged)\n  //   (collateral and credit outputs are NOT pinned here — they belong to the\n  //   paired rollIn / swap; vault.roll authorizes the spend on the borrower\n  //   side, rollIn validates the new vault's collateralisation)\n  function rollOut(pubkey borrowerPk, signature borrowerSig, int vaultIdx, int oldMintedAmount, int collateral,\n                   int outIdxPool, int expectedDischarge) {\n    require(oldMintedAmount > 0, \"zero amount\");\n    require(oldMintedAmount <= totalDebitOutstanding, \"exceeds outstanding\");\n    require(expectedDischarge == oldMintedAmount, \"discharge must equal par\");\n    require(tx.time < maturity, \"old pool matured\");\n    require(checkSig(borrowerSig, borrowerPk), \"invalid borrower sig\");\n\n    require(\n      tx.inputs[vaultIdx].scriptPubKey == new BondMint(\n        borrowerPk, debitAssetId, debitCtrlId, oldMintedAmount, collateral, maturity, auctionWindow, exit\n      ),\n      \"vault input mismatch\"\n    );\n\n    let debitGroup = tx.assetGroups.find(debitAssetId);\n    require(debitGroup.sumInputs == debitGroup.sumOutputs + oldMintedAmount, \"debit not burned exactly oldMintedAmount\");\n    let creditGroup = tx.assetGroups.find(creditAssetId);\n    require(creditGroup.delta == 0, \"credit must not move during roll\");\n    let ccGroup = tx.assetGroups.find(creditCtrlId);\n    require(ccGroup.delta == 0, \"credit control changed\");\n    let dcGroup = tx.assetGroups.find(debitCtrlId);\n    require(dcGroup.delta == 0, \"debit control changed\");\n\n    int usdtNext = usdtBalance + expectedDischarge;\n    int debitNext = totalDebitOutstanding - oldMintedAmount;\n\n    require(\n      tx.outputs[outIdxPool].scriptPubKey == new RepaymentPool(\n        usdtAssetId, creditAssetId, creditCtrlId, debitAssetId, debitCtrlId, ticker,\n        oraclePk, oracleMaxAgeSeconds, initRatioBps, liqThresholdBps, maturity, auctionWindow, auctionDiscountBps,\n        usdtNext, totalCreditOutstanding, debitNext, exit\n      ),\n      \"invalid pool recreation\"\n    );\n    require(tx.outputs[outIdxPool].assets.lookup(usdtAssetId) >= usdtNext, \"discharge not received\");\n    require(tx.outputs[outIdxPool].assets.lookup(creditCtrlId) >= 1, \"credit control not retained\");\n    require(tx.outputs[outIdxPool].assets.lookup(debitCtrlId) >= 1, \"debit control not retained\");\n  }\n\n  // ROLL IN — borrower opens a new vault on THIS pool (the next maturity).\n  // Same safety invariants as issue (oracle-priced over-collateralisation +\n  // dual-mint + control retention + borrower consent), but all output pins\n  // use witness indices so it composes with rollOut on the previous pool\n  // and a non_interactive_swap fill in the same atomic tx.\n  //\n  //   output[outIdxPool]:   this pool re-created (totalCredit + newMintedAmount,\n  //                         totalDebit + newMintedAmount)\n  //   output[outIdxCredit]: newMintedAmount credit → arbitrary destination.\n  //                         The scriptPubKey is NOT pinned by this contract:\n  //                         it could be a non_interactive_swap covenant that\n  //                         delivers to the maker, directly the maker's\n  //                         SingleSig, or any other valid destination. The\n  //                         borrower's Schnorr signature (SIGHASH_ALL by\n  //                         default) commits to the entire tx including this\n  //                         output's scriptPubKey, so the destination IS\n  //                         covered at signing time — the script just doesn't\n  //                         dictate its form, which is what makes atomic\n  //                         composition with non_interactive_swap possible.\n  //   output[outIdxVault]:  new BondMint vault holding newCollateral + debit\n  function rollIn(int newMintedAmount, int newCollateral, pubkey borrowerPk, signature borrowerSig,\n                  int oraclePrice, int oracleTime, signature oracleSig,\n                  int outIdxPool, int outIdxVault, int outIdxCredit) {\n    require(newMintedAmount > 0, \"zero issuance\");\n    require(newCollateral > 0, \"zero collateral\");\n    // Same deployment-safety invariants as issue() — rollIn is an alternate\n    // issuance entry that must reject misconfigured pools identically.\n    require(initRatioBps > liqThresholdBps, \"liq threshold must be below init ratio\");\n    require(liqThresholdBps > 0, \"liq threshold must be positive\");\n    require(auctionWindow > 0, \"auction window must be positive\");\n    require(auctionDiscountBps >= 0, \"negative discount\");\n    require(auctionDiscountBps < 10000, \"discount >= 100%\");\n    require(tx.time < maturity, \"new pool matured\");\n    require(checkSig(borrowerSig, borrowerPk), \"invalid borrower sig\");\n    require(oraclePrice > 0, \"invalid oracle price\");\n\n    int oracleAge = tx.offchainTime - oracleTime;\n    require(oracleAge >= 0, \"future-dated oracle\");\n    require(oracleAge <= oracleMaxAgeSeconds, \"stale oracle\");\n    let oracleMsg = sha256(ticker + oraclePrice + oracleTime);\n    require(checkSigFromStack(oracleSig, oraclePk, oracleMsg), \"invalid oracle signature\");\n\n    int collateralValue = newCollateral * oraclePrice / 100000000;\n    // Ceiling division — see explanation in issue(). Same dust-issuance\n    // defence on the alternate issuance entry.\n    int required = (newMintedAmount * initRatioBps + 9999) / 10000;\n    require(collateralValue >= required, \"undercollateralized at issuance\");\n\n    let creditGroup = tx.assetGroups.find(creditAssetId);\n    require(creditGroup.delta == newMintedAmount, \"credit delta mismatch\");\n    require(creditGroup.control == creditCtrlId, \"wrong credit control\");\n    let debitGroup = tx.assetGroups.find(debitAssetId);\n    require(debitGroup.delta == newMintedAmount, \"debit delta mismatch\");\n    require(debitGroup.control == debitCtrlId, \"wrong debit control\");\n    let ccGroup = tx.assetGroups.find(creditCtrlId);\n    require(ccGroup.delta == 0, \"credit control changed\");\n    let dcGroup = tx.assetGroups.find(debitCtrlId);\n    require(dcGroup.delta == 0, \"debit control changed\");\n\n    int creditNext = totalCreditOutstanding + newMintedAmount;\n    int debitNext = totalDebitOutstanding + newMintedAmount;\n\n    require(\n      tx.outputs[outIdxPool].scriptPubKey == new RepaymentPool(\n        usdtAssetId, creditAssetId, creditCtrlId, debitAssetId, debitCtrlId, ticker,\n        oraclePk, oracleMaxAgeSeconds, initRatioBps, liqThresholdBps, maturity, auctionWindow, auctionDiscountBps,\n        usdtBalance, creditNext, debitNext, exit\n      ),\n      \"invalid pool recreation\"\n    );\n    require(tx.outputs[outIdxPool].assets.lookup(usdtAssetId) >= usdtBalance, \"pool usdt short\");\n    require(tx.outputs[outIdxPool].assets.lookup(creditCtrlId) >= 1, \"credit control not retained\");\n    require(tx.outputs[outIdxPool].assets.lookup(debitCtrlId) >= 1, \"debit control not retained\");\n\n    require(tx.outputs[outIdxCredit].assets.lookup(creditAssetId) >= newMintedAmount, \"credit not delivered\");\n    // No scriptPubKey pin: the borrower's Schnorr sighash covers all outputs,\n    // so the credit destination IS implicitly committed by borrowerSig. This\n    // is what lets rollIn compose with a non_interactive_swap covenant fill.\n\n    require(\n      tx.outputs[outIdxVault].scriptPubKey == new BondMint(\n        borrowerPk, debitAssetId, debitCtrlId, newMintedAmount, newCollateral, maturity, auctionWindow, exit\n      ),\n      \"invalid new vault\"\n    );\n    require(tx.outputs[outIdxVault].value >= newCollateral, \"collateral not locked\");\n    require(tx.outputs[outIdxVault].assets.lookup(debitAssetId) >= newMintedAmount, \"debit not custodied in vault\");\n  }\n\n  // LIQUIDATE — pre-maturity MARGIN CALL. Permissionless. Anyone can trigger\n  // when `collateralValue < liqThresholdBps × mintedAmount / 10000`. Same\n  // oracle-priced two-branch payout as acceptAuction (over-cover: pool gets\n  // mintedAmount × payRate / 10000 USDT, auctioneer takes obligation-equivalent\n  // collateral, excess → borrower; shortfall: pool gets collateralValue ×\n  // payRate / 10000 USDT, auctioneer takes all collateral, gap socialises via\n  // redemption rate).\n  //\n  //   input[vaultIdx]: the BondMint being liquidated\n  //   output[0]: pool re-created (usdt + liquidationUsdt, totalDebit - mintedAmount)\n  //   output[1]: collateral sats → auctioneer\n  //   output[2]: excess sats → borrower (over-cover branch only, when > dust)\n  function liquidate(pubkey borrowerPk, int vaultIdx, int mintedAmount, int collateral,\n                     int oraclePrice, int oracleTime, signature oracleSig, pubkey auctioneerPk) {\n    require(auctionDiscountBps >= 0, \"negative discount\");\n    require(auctionDiscountBps < 10000, \"discount >= 100%\");\n    require(mintedAmount > 0, \"zero amount\");\n    require(mintedAmount <= totalDebitOutstanding, \"exceeds outstanding\");\n    require(tx.time < maturity, \"matured; use acceptAuction\");\n    require(oraclePrice > 0, \"invalid oracle price\");\n\n    int oracleAge = tx.offchainTime - oracleTime;\n    require(oracleAge >= 0, \"future-dated oracle\");\n    require(oracleAge <= oracleMaxAgeSeconds, \"stale oracle\");\n    let oracleMsg = sha256(ticker + oraclePrice + oracleTime);\n    require(checkSigFromStack(oracleSig, oraclePk, oracleMsg), \"invalid oracle signature\");\n\n    require(\n      tx.inputs[vaultIdx].scriptPubKey == new BondMint(\n        borrowerPk, debitAssetId, debitCtrlId, mintedAmount, collateral, maturity, auctionWindow, exit\n      ),\n      \"vault input mismatch\"\n    );\n\n    let debitGroup = tx.assetGroups.find(debitAssetId);\n    require(debitGroup.sumInputs == debitGroup.sumOutputs + mintedAmount, \"debit not burned exactly mintedAmount\");\n    let creditGroup = tx.assetGroups.find(creditAssetId);\n    require(creditGroup.delta == 0, \"credit must not move on liquidation\");\n    let ccGroup = tx.assetGroups.find(creditCtrlId);\n    require(ccGroup.delta == 0, \"credit control changed\");\n    let dcGroup = tx.assetGroups.find(debitCtrlId);\n    require(dcGroup.delta == 0, \"debit control changed\");\n\n    int collateralValue = collateral * oraclePrice / 100000000;\n    // Health-factor gate: liquidation is allowed ONLY when the vault has\n    // fallen below the threshold. This is the invariant that keeps every\n    // vault in the pool covenant-thresholded healthy and credit tokens\n    // genuinely fungible.\n    int healthFloor = mintedAmount * liqThresholdBps / 10000;\n    require(collateralValue < healthFloor, \"vault still healthy\");\n\n    int debitNext = totalDebitOutstanding - mintedAmount;\n    int payRate = 10000 - auctionDiscountBps;\n\n    if (collateralValue >= mintedAmount) {\n      int collateralSold  = mintedAmount * 100000000 / oraclePrice;\n      int excess          = collateral - collateralSold;\n      int liquidationUsdt = mintedAmount * payRate / 10000;\n      int usdtNext        = usdtBalance + liquidationUsdt;\n      require(\n        tx.outputs[0].scriptPubKey == new RepaymentPool(\n          usdtAssetId, creditAssetId, creditCtrlId, debitAssetId, debitCtrlId, ticker,\n          oraclePk, oracleMaxAgeSeconds, initRatioBps, liqThresholdBps, maturity, auctionWindow, auctionDiscountBps,\n          usdtNext, totalCreditOutstanding, debitNext, exit\n        ),\n        \"invalid pool recreation\"\n      );\n      require(tx.outputs[0].assets.lookup(usdtAssetId) >= usdtNext, \"liquidation proceeds short\");\n      require(tx.outputs[0].assets.lookup(creditCtrlId) >= 1, \"credit control not retained\");\n      require(tx.outputs[0].assets.lookup(debitCtrlId) >= 1, \"debit control not retained\");\n      require(tx.outputs[1].value >= collateralSold, \"auctioneer underpaid\");\n      require(tx.outputs[1].scriptPubKey == new SingleSig(auctioneerPk), \"output 1 not auctioneer\");\n      if (excess > 330) {\n        require(tx.outputs[2].value >= excess, \"borrower underpaid\");\n        require(tx.outputs[2].scriptPubKey == new SingleSig(borrowerPk), \"output 2 not borrower\");\n      }\n    } else {\n      int liquidationUsdt = collateralValue * payRate / 10000;\n      int usdtNext        = usdtBalance + liquidationUsdt;\n      require(\n        tx.outputs[0].scriptPubKey == new RepaymentPool(\n          usdtAssetId, creditAssetId, creditCtrlId, debitAssetId, debitCtrlId, ticker,\n          oraclePk, oracleMaxAgeSeconds, initRatioBps, liqThresholdBps, maturity, auctionWindow, auctionDiscountBps,\n          usdtNext, totalCreditOutstanding, debitNext, exit\n        ),\n        \"invalid pool recreation\"\n      );\n      require(tx.outputs[0].assets.lookup(usdtAssetId) >= usdtNext, \"liquidation proceeds short\");\n      require(tx.outputs[0].assets.lookup(creditCtrlId) >= 1, \"credit control not retained\");\n      require(tx.outputs[0].assets.lookup(debitCtrlId) >= 1, \"debit control not retained\");\n      require(tx.outputs[1].value >= collateral, \"auctioneer underpaid\");\n      require(tx.outputs[1].scriptPubKey == new SingleSig(auctioneerPk), \"output 1 not auctioneer\");\n    }\n  }\n\n  // ACCEPT AUCTION — at/after maturity, in the auction window. Permissionless.\n  // Any auctioneer provides the USDT and takes the collateral; the discount\n  // is their profit.\n  //\n  //   over-cover  (collateralValue >= mintedAmount):\n  //     auctionUsdt    = mintedAmount   * (10000 - auctionDiscountBps) / 10000\n  //     collateralSold = mintedAmount   * 1e8 / oraclePrice          → auctioneer\n  //     excess         = collateral - collateralSold                 → borrower (if > 330)\n  //   shortfall   (collateralValue < mintedAmount):\n  //     auctionUsdt    = collateralValue * (10000 - auctionDiscountBps) / 10000\n  //     all collateral                                                → auctioneer\n  //\n  //   input[vaultIdx]: the BondMint being auctioned\n  //   output[0]: pool re-created (usdt + auctionUsdt, totalDebit - mintedAmount)\n  //   output[1]: collateral sats → auctioneer\n  //   output[2]: excess sats → borrower (over-cover branch only, when > dust)\n  function acceptAuction(pubkey borrowerPk, int vaultIdx, int mintedAmount, int collateral,\n                         int oraclePrice, int oracleTime, signature oracleSig, pubkey auctioneerPk) {\n    require(auctionDiscountBps >= 0, \"negative discount\");\n    require(auctionDiscountBps < 10000, \"discount >= 100%\");\n    require(mintedAmount > 0, \"zero amount\");\n    require(mintedAmount <= totalDebitOutstanding, \"exceeds outstanding\");\n    require(tx.time >= maturity, \"not yet matured\");\n    int windowEnd = maturity + auctionWindow;\n    require(tx.time < windowEnd, \"auction window closed\");\n    require(oraclePrice > 0, \"invalid oracle price\");\n\n    int oracleAge = tx.offchainTime - oracleTime;\n    require(oracleAge >= 0, \"future-dated oracle\");\n    require(oracleAge <= oracleMaxAgeSeconds, \"stale oracle\");\n    let oracleMsg = sha256(ticker + oraclePrice + oracleTime);\n    require(checkSigFromStack(oracleSig, oraclePk, oracleMsg), \"invalid oracle signature\");\n\n    require(\n      tx.inputs[vaultIdx].scriptPubKey == new BondMint(\n        borrowerPk, debitAssetId, debitCtrlId, mintedAmount, collateral, maturity, auctionWindow, exit\n      ),\n      \"vault input mismatch\"\n    );\n\n    let debitGroup = tx.assetGroups.find(debitAssetId);\n    require(debitGroup.sumInputs == debitGroup.sumOutputs + mintedAmount, \"debit not burned exactly mintedAmount\");\n    let creditGroup = tx.assetGroups.find(creditAssetId);\n    require(creditGroup.delta == 0, \"credit must not move on auction\");\n    let ccGroup = tx.assetGroups.find(creditCtrlId);\n    require(ccGroup.delta == 0, \"credit control changed\");\n    let dcGroup = tx.assetGroups.find(debitCtrlId);\n    require(dcGroup.delta == 0, \"debit control changed\");\n\n    // FOLLOW-UP: same overflow ceiling as `issue` on `collateral * oraclePrice`;\n    // and `mintedAmount * 100000000` overflows above ~92 BTC of par. Both fail\n    // closed; chunked auctions or a rescaled price unit lift the cap.\n    int collateralValue = collateral * oraclePrice / 100000000;\n    int debitNext = totalDebitOutstanding - mintedAmount;\n    int payRate = 10000 - auctionDiscountBps;\n\n    if (collateralValue >= mintedAmount) {\n      int collateralSold = mintedAmount * 100000000 / oraclePrice;\n      int excess         = collateral - collateralSold;\n      int auctionUsdt    = mintedAmount * payRate / 10000;\n      int usdtNext       = usdtBalance + auctionUsdt;\n      require(\n        tx.outputs[0].scriptPubKey == new RepaymentPool(\n          usdtAssetId, creditAssetId, creditCtrlId, debitAssetId, debitCtrlId, ticker,\n          oraclePk, oracleMaxAgeSeconds, initRatioBps, liqThresholdBps, maturity, auctionWindow, auctionDiscountBps,\n          usdtNext, totalCreditOutstanding, debitNext, exit\n        ),\n        \"invalid pool recreation\"\n      );\n      require(tx.outputs[0].assets.lookup(usdtAssetId) >= usdtNext, \"auction proceeds short\");\n      require(tx.outputs[0].assets.lookup(creditCtrlId) >= 1, \"credit control not retained\");\n      require(tx.outputs[0].assets.lookup(debitCtrlId) >= 1, \"debit control not retained\");\n      require(tx.outputs[1].value >= collateralSold, \"auctioneer underpaid\");\n      require(tx.outputs[1].scriptPubKey == new SingleSig(auctioneerPk), \"output 1 not auctioneer\");\n      if (excess > 330) {\n        require(tx.outputs[2].value >= excess, \"borrower underpaid\");\n        require(tx.outputs[2].scriptPubKey == new SingleSig(borrowerPk), \"output 2 not borrower\");\n      }\n    } else {\n      int auctionUsdt = collateralValue * payRate / 10000;\n      int usdtNext    = usdtBalance + auctionUsdt;\n      require(\n        tx.outputs[0].scriptPubKey == new RepaymentPool(\n          usdtAssetId, creditAssetId, creditCtrlId, debitAssetId, debitCtrlId, ticker,\n          oraclePk, oracleMaxAgeSeconds, initRatioBps, liqThresholdBps, maturity, auctionWindow, auctionDiscountBps,\n          usdtNext, totalCreditOutstanding, debitNext, exit\n        ),\n        \"invalid pool recreation\"\n      );\n      require(tx.outputs[0].assets.lookup(usdtAssetId) >= usdtNext, \"auction proceeds short\");\n      require(tx.outputs[0].assets.lookup(creditCtrlId) >= 1, \"credit control not retained\");\n      require(tx.outputs[0].assets.lookup(debitCtrlId) >= 1, \"debit control not retained\");\n      require(tx.outputs[1].value >= collateral, \"auctioneer underpaid\");\n      require(tx.outputs[1].scriptPubKey == new SingleSig(auctioneerPk), \"output 1 not auctioneer\");\n    }\n  }\n\n  // REDEEM — after the auction window closes, credit holders burn credit for\n  // pro-rata USDT. payout = amount * usdtBalance / totalCreditOutstanding.\n  // The rate is preserved under redemption alone, so fair pro-rata for every\n  // claim ordering.\n  //\n  //   output[0]: pool re-created (usdt - payout, totalCredit - amount)\n  //   output[1]: payout USDT → holder (SingleSig — clean single-owner exit)\n  function redeem(int amount, pubkey holderPk, signature holderSig) {\n    require(amount > 0, \"zero redeem\");\n    int redeemStart = maturity + auctionWindow;\n    require(tx.time >= redeemStart, \"auction window not closed\");\n    require(checkSig(holderSig, holderPk), \"invalid holder sig\");\n    require(amount <= totalCreditOutstanding, \"exceeds outstanding\");\n    require(totalCreditOutstanding > 0, \"no credit outstanding\");\n    require(usdtBalance > 0, \"pool empty\");\n\n    // FOLLOW-UP: `amount * usdtBalance` overflows int64 at large pool sizes.\n    // Fails closed; chunk redemptions or rearrange math to divide-before-\n    // multiply with controlled precision loss.\n    int payout = amount * usdtBalance / totalCreditOutstanding;\n    require(payout > 0, \"payout rounds to zero\");\n\n    let creditGroup = tx.assetGroups.find(creditAssetId);\n    require(creditGroup.sumInputs == creditGroup.sumOutputs + amount, \"credit not burned exactly amount\");\n    let ccGroup = tx.assetGroups.find(creditCtrlId);\n    require(ccGroup.delta == 0, \"credit control changed\");\n    let dcGroup = tx.assetGroups.find(debitCtrlId);\n    require(dcGroup.delta == 0, \"debit control changed\");\n\n    int usdtNext   = usdtBalance - payout;\n    int creditNext = totalCreditOutstanding - amount;\n\n    require(\n      tx.outputs[0].scriptPubKey == new RepaymentPool(\n        usdtAssetId, creditAssetId, creditCtrlId, debitAssetId, debitCtrlId, ticker,\n        oraclePk, oracleMaxAgeSeconds, initRatioBps, liqThresholdBps, maturity, auctionWindow, auctionDiscountBps,\n        usdtNext, creditNext, totalDebitOutstanding, exit\n      ),\n      \"invalid pool recreation\"\n    );\n    require(tx.outputs[0].assets.lookup(usdtAssetId) >= usdtNext, \"pool usdt short\");\n    require(tx.outputs[0].assets.lookup(creditCtrlId) >= 1, \"credit control not retained\");\n    require(tx.outputs[0].assets.lookup(debitCtrlId) >= 1, \"debit control not retained\");\n\n    require(tx.outputs[1].assets.lookup(usdtAssetId) >= payout, \"holder underpaid\");\n    require(tx.outputs[1].scriptPubKey == new SingleSig(holderPk), \"redeem dest not holder\");\n  }\n}\n";

export const controlled_mint = "// Controlled Mint Contract\n// Demonstrates asset group introspection primitives\n//\n// This contract manages a token minting authority where:\n// 1. mint() - Authority can mint new tokens (delta > 0), control asset required\n// 2. burn() - Anyone can burn tokens (delta < 0), no control needed\n// 3. lockSupply() - Authority burns the control asset to lock supply forever\n//\n// Asset groups provide aggregate views of asset flows across all inputs/outputs,\n// enabling balance verification without iterating individual UTXOs.\n\noptions {\n  server = server;\n  exit = 288;\n}\n\ncontract ControlledMint(\n  bytes32 tokenAssetId,\n  bytes32 ctrlAssetId,\n  pubkey issuerPk\n) {\n  // Mint: delta > 0, control asset present and retained\n  function mint(int amount, pubkey recipientPk, signature issuerSig) {\n    let tokenGroup = tx.assetGroups.find(tokenAssetId);\n    require(tokenGroup.delta == amount, \"delta mismatch\");\n    require(tokenGroup.control == ctrlAssetId, \"wrong control\");\n\n    let ctrlGroup = tx.assetGroups.find(ctrlAssetId);\n    require(ctrlGroup.delta == 0, \"ctrl supply changed\");\n\n    require(tx.outputs[0].assets.lookup(tokenAssetId) >= amount, \"mint short\");\n    require(tx.outputs[0].scriptPubKey == new SingleSig(recipientPk), \"wrong dest\");\n    require(checkSig(issuerSig, issuerPk), \"bad sig\");\n  }\n\n  // Burn: delta < 0, no control asset needed\n  function burn(int amount, signature ownerSig, pubkey ownerPk) {\n    let tokenGroup = tx.assetGroups.find(tokenAssetId);\n    require(tokenGroup.sumInputs >= tokenGroup.sumOutputs + amount, \"burn short\");\n    require(checkSig(ownerSig, ownerPk), \"bad sig\");\n  }\n\n  // Lock supply forever: burn the control asset\n  function lockSupply(signature issuerSig) {\n    let ctrlGroup = tx.assetGroups.find(ctrlAssetId);\n    require(ctrlGroup.sumOutputs == 0, \"ctrl not burned\");\n    require(checkSig(issuerSig, issuerPk), \"bad sig\");\n  }\n}\n";

export const fee_adapter = "// Fee Adapter Contract\n// Demonstrates arithmetic expressions with tx input/output verification\n//\n// This contract implements a fee-taking adapter where:\n// 1. execute() - Processes a payment, verifying output asset balances\n// 2. The output must preserve assets minus fee\n//\n// Uses asset lookups on tx.inputs and tx.outputs with arithmetic\n// comparisons for balance verification.\n\noptions {\n  server = server;\n  exit = 144;\n}\n\ncontract FeeAdapter(\n  pubkey senderPk,\n  pubkey operatorPk,\n  pubkey recipientPk,\n  bytes32 paymentAssetId,\n  int minFee\n) {\n  // Execute: process payment with fee deduction\n  // Verifies that the output asset balance reflects the fee deduction\n  function execute(signature senderSig, int fee) {\n    // Fee must be at least the minimum\n    require(fee >= minFee, \"fee below minimum\");\n\n    // Input must contain the payment asset\n    require(tx.inputs[0].assets.lookup(paymentAssetId) > 0, \"no payment asset in input\");\n\n    // Output must contain the payment asset (minus fee)\n    require(tx.outputs[0].assets.lookup(paymentAssetId) > 0, \"no payment asset in output\");\n\n    // Sender must sign\n    require(checkSig(senderSig, senderPk), \"invalid sender signature\");\n  }\n\n  // Adjust: operator adjusts fee parameters\n  function adjust(signature operatorSig) {\n    // Operator must sign\n    require(checkSig(operatorSig, operatorPk), \"invalid operator signature\");\n  }\n}\n";

export const fuji_safe = "// Contract configuration options\noptions {\n  // Arkade operator key (always external, never a contract party)\n  server = server;\n  \n  // Exit timelock: 24 hours (144 blocks)\n  exit = 144;\n}\n\n// Fuji Safe Contract\ncontract FujiSafe(\n  // The asset commitment hash (client-side validated)\n  bytes assetCommitmentHash,\n  // The amount being borrowed\n  int borrowAmount,\n  // The borrower's public key\n  pubkey borrowerPk,\n  // The treasury's public key\n  pubkey treasuryPk,\n  // The expiration timeout in blocks\n  int expirationTimeout,\n  // The price level for liquidation\n  int priceLevel,\n  // The setup timestamp\n  int setupTimestamp,\n  // The oracle's public key\n  pubkey oraclePk,\n  // The asset pair identifier\n  bytes assetPair\n) {\n  // Helper function to verify Fuji token burning via Taproot output\n  // Takes the pubkey to use as the internal key for the P2TR output\n  function verifyFujiBurning(pubkey internalKey) internal {\n    // In Taproot, we verify the output is a P2TR that commits to our asset\n    // Using the provided pubkey as the internal key\n    bytes p2trScript = new P2TR(internalKey, assetCommitmentHash);\n    \n    // Verify output 0 has the correct P2TR scriptPubKey and value\n    require(tx.outputs[0].scriptPubKey == p2trScript, \"P2TR output mismatch\");\n    require(tx.outputs[0].value == borrowAmount, \"Value mismatch\");\n  }\n\n  // Claim: Treasury can unlock all collateral after expiration when burning Fuji\n  function claim(signature treasurySig) {\n    // Check that expiration timeout has passed\n    require(tx.time >= expirationTimeout, \"Expiration timeout not reached\");\n    \n    // Verify burning of Fuji token using treasury key\n    verifyFujiBurning(treasuryPk);\n    \n    // Require treasury signature\n    require(checkSig(treasurySig, treasuryPk), \"Invalid treasury signature\");\n  }\n  \n  // Liquidation: Treasury can unlock all collateral with attestation price below the liquidation target\n  function liquidate(int currentPrice, signature oracleSig, signature treasurySig) {\n    // Check price is below liquidation threshold\n    require(currentPrice < priceLevel, \"Price not below liquidation threshold\");\n    \n    // Verify timestamp is after setup\n    require(tx.time >= setupTimestamp, \"Timestamp before setup\");\n    \n    // Create message for oracle signature verification\n    bytes message = sha256(assetPair);\n    \n    // Verify oracle signature on price data\n    require(checkSigFromStack(oracleSig, oraclePk, message), \"Invalid oracle signature\");\n    \n    // Verify burning of Fuji token using treasury key\n    verifyFujiBurning(treasuryPk);\n    \n    // Require treasury signature\n    require(checkSig(treasurySig, treasuryPk), \"Invalid treasury signature\");\n  }\n  \n  // Private Redemption: Only owner can unlock all collateral with key when burning Fuji\n  function redeem(signature borrowerSig) {\n    // Verify burning of Fuji token using borrower key\n    verifyFujiBurning(borrowerPk);\n    \n    // Require borrower signature\n    require(checkSig(borrowerSig, borrowerPk), \"Invalid borrower signature\");\n  }\n  \n  // Treasury Renew: Treasury can unilaterally renew the expiration time\n  function renew(signature treasurySig) {\n    int currentValue = tx.input.current.value;\n\n    // Recreate same contract with identical parameters\n    require(\n      tx.outputs[0].scriptPubKey == new FujiSafe(\n        assetCommitmentHash, borrowAmount, borrowerPk, treasuryPk,\n        expirationTimeout, priceLevel, setupTimestamp, oraclePk, assetPair\n      ),\n      \"contract mismatch\"\n    );\n    require(tx.outputs[0].value == currentValue, \"Value mismatch\");\n\n    // Require treasury signature\n    require(checkSig(treasurySig, treasuryPk), \"Invalid treasury signature\");\n  }\n} ";

export const inventory_hedge = "// InventoryHedge Contract\n//\n// A perpetual, BTC-settled, fully-collateralized market-maker inventory hedge.\n// See docs/mm-residual-hedge.md. It generalizes StabilityVault: a BTC UTXO is\n// split between two parties so a market-making desk can convert residual BTC\n// inventory into a fiat-denominated claim — delta-flat, self-custodied, no CEX.\n//\n// Legs (doc §2):\n//   - CLAIM leg (claimPk): the desk. Holds a fiat claim `targetFiat`,\n//     delta-flat in fiat terms.\n//   - LONG leg (longPk): the provider / BTC treasury. Holds the residual BTC\n//     upside and posts the over-collateral.\n//   Funding flows LONG -> CLAIM: the cost of self-custodied leverage.\n//\n// Perpetual: no maturity. Oracle-marked. Fully collateralized — settlement is\n// always a clamp into [0, totalCollateral], so there is no liquidation.\n//\n// Multi-currency (doc §3): `ticker` is the BTC/<fiat> feed id\n// (e.g. sha256(\"BTC/USD\")). One instance per pair; the same contract serves\n// USD/BRL/CHF/EUR purely by parameterization. Every fiat claim leg is short BTC,\n// so the whole desk collapses to one aggregate BTC-delta book balanced off-chain.\n//\n// Funding model (fiat-compound, interleaved /1e6 to stay in int64):\n//   elapsed       = tx.offchainTime - lastUpdate\n//   newTargetFiat = targetFiat × (1 + fundingRatePerSec × elapsed / 1e12)\n//   fundingRatePerSec is a signed fixed-point fraction at scale 1e12. The\n//   dynamic, imbalance-driven rate (doc §4) is computed OFF-chain by the desk's\n//   risk engine and supplied to updateFunding; on-chain logic is the >= 0 guard\n//   plus the accrual roll-forward.\n//\n// Settlement math (single shape across redeem, withdraw, removeCapital):\n//   newTargetFiat = targetFiat × (1 + fundingRatePerSec × elapsed / 1e12)\n//   claimRaw      = newTargetFiat × 1e8 / oraclePrice\n//   claimPayout   = clamp(claimRaw, 0, totalCollateral)\n//   longPayout    = totalCollateral − claimPayout\n// At a 1.5:1 ratio the desk is made whole to a ~60% drawdown (doc §2); beyond\n// that the buffer is exhausted and the claim leg carries the tail.\n//\n// Oracle model (Fuji-style signed feed):\n//   msg = sha256(ticker || price || timestamp), price/timestamp as 8-byte LE.\n//   At settlement the caller supplies (oraclePrice, oracleTime, oracleSig);\n//   freshness: tx.offchainTime - oracleTime <= 600 seconds. `tx.offchainTime`\n//   is the TEE-introspector wallclock (unix seconds), distinct from `tx.time`\n//   (Bitcoin nLockTime, block height).\n\nimport \"single_sig.ark\";\n\noptions {\n  server = server;\n  exit = exit;\n}\n\ncontract InventoryHedge(\n  pubkey  claimPk,            // holder of the fiat claim leg (the hedging desk)\n  pubkey  longPk,            // collateral provider / BTC long leg (treasury)\n  pubkey  oraclePk,          // price feed key; only its signatures are accepted\n  bytes32 ticker,            // BTC/<fiat> feed identifier (e.g. sha256(\"BTC/USD\"))\n  int     targetFiat,        // claim leg's fiat value (minor units); mutates on funding\n  int     totalCollateral,   // sats locked; mutates on add/removeCapital\n  int     fundingRatePerSec, // signed fixed-point at scale 1e12; runtime updates enforce >= 0 (see updateFunding); a negative *initial* rate is not prevented at construction and should not be used for a hedging vault\n  int     lastUpdate,        // unix seconds; basis for funding accrual\n  int     collateralRatioPct,// min collateral ratio for removeCapital (50 = 1.5:1)\n  int     exit               // exit timelock in blocks\n) {\n\n  // -------------------------------------------------------------------------\n  // TRANSFER — desk reassigns the claim leg. Pure key swap, no oracle.\n  // -------------------------------------------------------------------------\n  function transfer(signature claimSig, pubkey newClaimPk) {\n    require(checkSig(claimSig, claimPk), \"invalid claim sig\");\n\n    require(\n      tx.outputs[0].scriptPubKey == new InventoryHedge(\n        newClaimPk, longPk, oraclePk, ticker,\n        targetFiat, totalCollateral, fundingRatePerSec, lastUpdate,\n        collateralRatioPct, exit\n      ),\n      \"invalid transfer output\"\n    );\n    require(tx.outputs[0].value >= totalCollateral, \"collateral not preserved\");\n  }\n\n  // -------------------------------------------------------------------------\n  // UPDATE FUNDING — provider rolls accrued funding into targetFiat and sets a\n  // new rate. The rate must be >= 0: a negative rate would let the provider\n  // drain the desk. The dynamic, imbalance-driven value is computed off-chain\n  // (doc §4) and supplied here; on-chain we only guard the sign and the accrual.\n  // -------------------------------------------------------------------------\n  function updateFunding(signature longSig, int newFundingRatePerSec) {\n    require(checkSig(longSig, longPk), \"invalid long-leg sig\");\n    require(newFundingRatePerSec >= 0, \"negative funding rate disallowed\");\n\n    int elapsed           = tx.offchainTime - lastUpdate;\n    require(elapsed >= 0, \"clock regression\");\n    int rateElapsedScaled = fundingRatePerSec * elapsed / 1000000;\n    int delta             = targetFiat * rateElapsedScaled / 1000000;\n    int newTargetFiat     = targetFiat + delta;\n    require(newTargetFiat > 0, \"claim wiped by funding\");\n\n    // Anti-grief: if the current rate is non-zero the accrual must be non-zero,\n    // else advancing lastUpdate would silently suppress funding owed the desk.\n    // A no-accrual update is only legitimate when the current rate is already 0.\n    if (fundingRatePerSec != 0) {\n      require(delta > 0, \"no accrual; wait longer\");\n    }\n\n    require(\n      tx.outputs[0].scriptPubKey == new InventoryHedge(\n        claimPk, longPk, oraclePk, ticker,\n        newTargetFiat, totalCollateral, newFundingRatePerSec, tx.offchainTime,\n        collateralRatioPct, exit\n      ),\n      \"invalid update output\"\n    );\n    require(tx.outputs[0].value >= totalCollateral, \"collateral not preserved\");\n  }\n\n  // -------------------------------------------------------------------------\n  // ADD CAPITAL — provider tops up collateral (doc §2 margin top-up cycle).\n  // More collateral is always strictly better for the desk; no ratio check.\n  // -------------------------------------------------------------------------\n  function addCapital(signature longSig, int amount) {\n    require(checkSig(longSig, longPk), \"invalid long-leg sig\");\n    require(amount > 0, \"zero amount\");\n\n    int newTotalCollateral = totalCollateral + amount;\n\n    require(\n      tx.outputs[0].scriptPubKey == new InventoryHedge(\n        claimPk, longPk, oraclePk, ticker,\n        targetFiat, newTotalCollateral, fundingRatePerSec, lastUpdate,\n        collateralRatioPct, exit\n      ),\n      \"invalid output\"\n    );\n    require(tx.outputs[0].value >= newTotalCollateral, \"collateral not deposited\");\n  }\n\n  // -------------------------------------------------------------------------\n  // REMOVE CAPITAL — provider reclaims excess collateral, but the remaining\n  // position must still cover the claim at collateralRatioPct (doc §2 bound).\n  // Accrued funding is included in the check without rolling it into the vault.\n  // -------------------------------------------------------------------------\n  function removeCapital(\n    signature longSig,\n    int       amount,\n    int       oraclePrice,\n    int       oracleTime,\n    signature oracleSig\n  ) {\n    require(checkSig(longSig, longPk), \"invalid long-leg sig\");\n    require(amount > 0, \"zero amount\");\n    require(oraclePrice > 0, \"invalid oracle price\");\n\n    int oracleAge = tx.offchainTime - oracleTime;\n    require(oracleAge >= 0, \"future-dated oracle\");\n    require(oracleAge <= 600, \"stale oracle\");\n\n    let oracleMsg = sha256(ticker + oraclePrice + oracleTime);\n    require(checkSigFromStack(oracleSig, oraclePk, oracleMsg), \"invalid oracle signature\");\n\n    int elapsed            = tx.offchainTime - lastUpdate;\n    require(elapsed >= 0, \"clock regression\");\n    int rateElapsedScaled  = fundingRatePerSec * elapsed / 1000000;\n    int delta              = targetFiat * rateElapsedScaled / 1000000;\n    int newTargetFiat      = targetFiat + delta;\n    // Defense-in-depth: a non-positive claim would make minCollateral <= 0 and\n    // the ratio check trivially pass, letting the long leg drain the vault. The\n    // runtime invariant is fundingRatePerSec >= 0 (enforced by updateFunding),\n    // but a negative *initial* rate is not prevented at construction, so guard\n    // here too — matching updateFunding. A wiped claim must settle via withdraw,\n    // not be reclaimed-around via removeCapital.\n    require(newTargetFiat > 0, \"claim wiped by funding\");\n    int currentClaimBase   = newTargetFiat * 100000000 / oraclePrice;\n    int minCollateral      = currentClaimBase * (100 + collateralRatioPct) / 100;\n    int newTotalCollateral = totalCollateral - amount;\n    require(newTotalCollateral >= minCollateral, \"would breach collateral ratio\");\n\n    require(\n      tx.outputs[0].scriptPubKey == new InventoryHedge(\n        claimPk, longPk, oraclePk, ticker,\n        targetFiat, newTotalCollateral, fundingRatePerSec, lastUpdate,\n        collateralRatioPct, exit\n      ),\n      \"invalid vault output\"\n    );\n    require(tx.outputs[0].value >= newTotalCollateral, \"vault underfunded\");\n    require(tx.outputs[1].scriptPubKey == new SingleSig(longPk), \"output 1 not long leg\");\n    require(tx.outputs[1].value >= amount, \"long leg underpaid\");\n  }\n\n  // -------------------------------------------------------------------------\n  // REDEEM — desk redeems its fiat claim for BTC at the oracle price.\n  // BTC-native at the index price (doc §2: no perp-spot basis). No exit fee.\n  //   claimRaw    = newTargetFiat × 1e8 / oraclePrice\n  //   claimPayout = clamp(claimRaw, 0, totalCollateral); remainder to long leg.\n  // -------------------------------------------------------------------------\n  function redeem(\n    signature claimSig,\n    int       oraclePrice,\n    int       oracleTime,\n    signature oracleSig\n  ) {\n    require(checkSig(claimSig, claimPk), \"invalid claim sig\");\n    require(oraclePrice > 0, \"invalid oracle price\");\n\n    int oracleAge = tx.offchainTime - oracleTime;\n    require(oracleAge >= 0, \"future-dated oracle\");\n    require(oracleAge <= 600, \"stale oracle\");\n\n    let oracleMsg = sha256(ticker + oraclePrice + oracleTime);\n    require(checkSigFromStack(oracleSig, oraclePk, oracleMsg), \"invalid oracle signature\");\n\n    int elapsed           = tx.offchainTime - lastUpdate;\n    require(elapsed >= 0, \"clock regression\");\n    int rateElapsedScaled = fundingRatePerSec * elapsed / 1000000;\n    int delta             = targetFiat * rateElapsedScaled / 1000000;\n    int newTargetFiat     = targetFiat + delta;\n    int claimRaw          = newTargetFiat * 100000000 / oraclePrice;\n\n    // No require(newTargetFiat > 0) here, on purpose: if funding has driven the\n    // claim non-positive, claimRaw <= 0 and the clamp routes the ENTIRE\n    // collateral to the long leg — the correct terminal outcome for a wiped\n    // claim. A hard guard would abort this legitimate settlement, including the\n    // long leg's own withdraw. The clamp, not a require, is the invariant here.\n    if (claimRaw <= 0) {\n      require(tx.outputs[0].value >= totalCollateral, \"long leg underpaid\");\n      require(tx.outputs[0].scriptPubKey == new SingleSig(longPk), \"output 0 not long leg\");\n    } else {\n      if (claimRaw >= totalCollateral) {\n        require(tx.outputs[0].value >= totalCollateral, \"claim underpaid\");\n        require(tx.outputs[0].scriptPubKey == new SingleSig(claimPk), \"output 0 not claim\");\n      } else {\n        require(tx.outputs[0].value >= claimRaw, \"claim underpaid\");\n        require(tx.outputs[0].scriptPubKey == new SingleSig(claimPk), \"output 0 not claim\");\n        int longPayout = totalCollateral - claimRaw;\n        if (longPayout > 330) {\n          require(tx.outputs[1].value >= longPayout, \"long leg underpaid\");\n          require(tx.outputs[1].scriptPubKey == new SingleSig(longPk), \"output 1 not long leg\");\n        }\n      }\n    }\n  }\n\n  // -------------------------------------------------------------------------\n  // WITHDRAW — treasury-driven settlement; identical clamp math.\n  // -------------------------------------------------------------------------\n  function withdraw(\n    signature longSig,\n    int       oraclePrice,\n    int       oracleTime,\n    signature oracleSig\n  ) {\n    require(checkSig(longSig, longPk), \"invalid long-leg sig\");\n    require(oraclePrice > 0, \"invalid oracle price\");\n\n    int oracleAge = tx.offchainTime - oracleTime;\n    require(oracleAge >= 0, \"future-dated oracle\");\n    require(oracleAge <= 600, \"stale oracle\");\n\n    let oracleMsg = sha256(ticker + oraclePrice + oracleTime);\n    require(checkSigFromStack(oracleSig, oraclePk, oracleMsg), \"invalid oracle signature\");\n\n    int elapsed           = tx.offchainTime - lastUpdate;\n    require(elapsed >= 0, \"clock regression\");\n    int rateElapsedScaled = fundingRatePerSec * elapsed / 1000000;\n    int delta             = targetFiat * rateElapsedScaled / 1000000;\n    int newTargetFiat     = targetFiat + delta;\n    int claimRaw          = newTargetFiat * 100000000 / oraclePrice;\n\n    // No require(newTargetFiat > 0) here, on purpose: if funding has driven the\n    // claim non-positive, claimRaw <= 0 and the clamp routes the ENTIRE\n    // collateral to the long leg — the correct terminal outcome for a wiped\n    // claim. A hard guard would abort this legitimate settlement, including the\n    // long leg's own withdraw. The clamp, not a require, is the invariant here.\n    if (claimRaw <= 0) {\n      require(tx.outputs[0].value >= totalCollateral, \"long leg underpaid\");\n      require(tx.outputs[0].scriptPubKey == new SingleSig(longPk), \"output 0 not long leg\");\n    } else {\n      if (claimRaw >= totalCollateral) {\n        require(tx.outputs[0].value >= totalCollateral, \"claim underpaid\");\n        require(tx.outputs[0].scriptPubKey == new SingleSig(claimPk), \"output 0 not claim\");\n      } else {\n        require(tx.outputs[0].value >= claimRaw, \"claim underpaid\");\n        require(tx.outputs[0].scriptPubKey == new SingleSig(claimPk), \"output 0 not claim\");\n        int longPayout = totalCollateral - claimRaw;\n        if (longPayout > 330) {\n          require(tx.outputs[1].value >= longPayout, \"long leg underpaid\");\n          require(tx.outputs[1].scriptPubKey == new SingleSig(longPk), \"output 1 not long leg\");\n        }\n      }\n    }\n  }\n}\n";

export const htlc = "// Contract configuration options\noptions {\n  // Server key \n  server = server;\n  \n  // Renewal timelock: 7 days (1008 blocks)\n  // The contract must be renewed with the Arkade server within this period\n  renew = 1008;\n  \n  // Exit timelock: 24 hours (144 blocks)\n  // Time required to exit unilaterally without server involvement\n  exit = 144;\n}\n\ncontract HTLC(\n  pubkey sender,\n  pubkey receiver,\n  bytes hash,\n  int refundTime\n) {\n  // Cooperative close path\n  function together(signature senderSig, signature receiverSig) {\n    require(checkMultisig([sender, receiver], [senderSig, receiverSig]));\n  }\n  \n  // Refund path\n  // This will automatically be compiled into:\n  // 1. Cooperative path: checkSig(sender) && after refundTime && checkSig(server)\n  // 2. Exit path: checkSig(sender) && after refundTime && after 24 hours\n  function refund(signature senderSig) {\n    require(checkSig(senderSig, sender));\n    require(tx.time >= refundTime);\n  }\n  \n  // Claim path\n  // This will automatically be compiled into:\n  // 1. Cooperative path: checkSig(receiver) && sha256(preimage) == hash && checkSig(server)\n  // 2. Exit path: checkSig(receiver) && sha256(preimage) == hash && after 24 hours\n  function claim(signature receiverSig, bytes preimage) {\n    require(checkSig(receiverSig, receiver));\n    require(sha256(preimage) == hash);\n  }\n} ";

export const nft_mint = "// NFT Minting Contract\n// Demonstrates isFresh and assetId properties for unique asset creation\n//\n// This contract enforces:\n// 1. Each NFT is fresh (newly created in this transaction)\n// 2. NFTs are controlled by a collection control asset\n// 3. Only one unit per NFT (delta = 1)\n//\n// Key group properties used:\n// - group.isFresh: Detects if asset was created in current transaction\n// - group.delta: Ensures exactly 1 unit is minted\n// - group.control: Verifies collection membership\n\noptions {\n    server = server;\n    exit = 288;\n}\n\ncontract NFTMint(\n    bytes32 collectionCtrlId,\n    pubkey issuerPk\n) {\n    // Mint a new NFT: must be fresh with delta=1\n    function mint(bytes32 nftAssetId, pubkey recipientPk, signature issuerSig) {\n        let nftGroup = tx.assetGroups.find(nftAssetId);\n\n        // Must be a brand new asset (genesis in this tx)\n        require(nftGroup.isFresh == 1, \"must be fresh\");\n\n        // Must mint exactly 1 (NFT)\n        require(nftGroup.delta == 1, \"must mint exactly 1\");\n\n        // Must be controlled by the collection\n        require(nftGroup.control == collectionCtrlId, \"wrong collection\");\n\n        // Control asset must be retained (delta == 0)\n        let ctrlGroup = tx.assetGroups.find(collectionCtrlId);\n        require(ctrlGroup.delta == 0, \"control must be retained\");\n\n        // NFT goes to recipient\n        require(tx.outputs[0].assets.lookup(nftAssetId) == 1, \"NFT not in output\");\n        require(tx.outputs[0].scriptPubKey == new SingleSig(recipientPk), \"wrong recipient\");\n\n        require(checkSig(issuerSig, issuerPk), \"bad issuer sig\");\n    }\n\n    // Transfer existing NFT (not fresh)\n    function transfer(bytes32 nftAssetId, pubkey newOwnerPk, signature ownerSig, pubkey ownerPk) {\n        let nftGroup = tx.assetGroups.find(nftAssetId);\n\n        // Must NOT be fresh (existing asset)\n        require(nftGroup.isFresh == 0, \"cannot be fresh\");\n\n        // Must be a transfer (delta == 0)\n        require(nftGroup.delta == 0, \"must be transfer\");\n\n        // Must be controlled by the collection\n        require(nftGroup.control == collectionCtrlId, \"wrong collection\");\n\n        // NFT goes to new owner\n        require(tx.outputs[0].assets.lookup(nftAssetId) == 1, \"NFT not in output\");\n        require(tx.outputs[0].scriptPubKey == new SingleSig(newOwnerPk), \"wrong dest\");\n\n        require(checkSig(ownerSig, ownerPk), \"bad owner sig\");\n    }\n\n    // Burn an NFT (delta = -1)\n    function burn(bytes32 nftAssetId, signature ownerSig, pubkey ownerPk) {\n        let nftGroup = tx.assetGroups.find(nftAssetId);\n\n        // Must be existing asset\n        require(nftGroup.isFresh == 0, \"cannot burn fresh asset\");\n\n        // Must burn exactly 1 (negative delta)\n        require(nftGroup.sumInputs >= nftGroup.sumOutputs + 1, \"must burn exactly 1\");\n\n        require(checkSig(ownerSig, ownerPk), \"bad owner sig\");\n    }\n}\n";

export const non_interactive_swap = "// Non-Interactive Swap Contract\n// Allows users to exchange assets without requiring both parties to be online simultaneously.\n//\n// VTXO\n// - Cooperative path: Server emulates/validates introspection, co-signs for fast settlement\n// - Exit path: N-of-N user signatures when introspection is used (pure Bitcoin fallback)\n//\n// Paths:\n// - swap cooperative: takerSig + serverSig + OP_INSPECT* (trustless via introspection)\n// - swap exit: makerSig + takerSig + CSV (N-of-N users, pure Bitcoin)\n// - cancel cooperative: makerSig + serverSig + after(expiration)\n// - cancel exit: makerSig + after(expiration) + CSV (normal exit)\n\noptions {\n  // Server key is injected from getInfo(), not passed in constructor\n  server = server;\n  // Exit delay: 144 blocks (~24 hours) for unilateral recovery\n  exit = 144;\n}\n\ncontract NonInteractiveSwap(\n  // Maker's public key (creator of the swap offer)\n  pubkey makerPk,\n  // Asset ID the maker is offering (locked in this contract)\n  bytes32 offerAssetId,\n  // Amount of offer asset locked\n  int offerAmount,\n  // Asset ID the maker wants to receive\n  bytes32 wantAssetId,\n  // Amount of want asset required for the swap\n  int wantAmount,\n  // Expiration timestamp (block height) after which maker can cancel\n  int expirationTime\n) {\n  // Swap: Any taker can fulfill - introspection makes cooperative path trustless\n  // Cooperative: takerSig + serverSig + OP_INSPECT* (server validates outputs)\n  // Exit: makerSig + takerSig + CSV (N-of-N users, pure Bitcoin - no introspection)\n  function swap(pubkey takerPk, signature takerSig) {\n    // Taker must sign to authorize spending their wantAsset\n    require(checkSig(takerSig, takerPk), \"invalid taker signature\");\n\n    // Introspection verifies the atomic exchange:\n    // Output 0: maker receives wantAsset\n    require(\n      tx.outputs[0].assets.lookup(wantAssetId) >= wantAmount,\n      \"insufficient want asset for maker\"\n    );\n    require(\n      tx.outputs[0].scriptPubKey == new SingleSig(makerPk),\n      \"output 0 not spendable by maker\"\n    );\n\n    // Output 1: taker receives offerAsset\n    require(\n      tx.outputs[1].assets.lookup(offerAssetId) >= offerAmount,\n      \"insufficient offer asset for taker\"\n    );\n    require(\n      tx.outputs[1].scriptPubKey == new SingleSig(takerPk),\n      \"output 1 not spendable by taker\"\n    );\n  }\n\n  // Cancel: Maker reclaims after expiration if no taker\n  // No introspection used, so normal exit path applies\n  // Cooperative: makerSig + serverSig + after(expiration)\n  // Exit: makerSig + after(expiration) + CSV\n  function cancel(signature makerSig) {\n    require(tx.time >= expirationTime, \"swap not expired\");\n    require(checkSig(makerSig, makerPk), \"invalid maker signature\");\n  }\n}\n";

export const cash_secured_put = "// CashSecuredPut Contract\n//\n// Bitcoin-native, single-locked, physically-settled European cash-secured\n// put. Mirror of CoveredCall. Faithful match to Rysk Finance v12.\n//\n// Single-sided collateral lockup:\n//   - Seller locks `stableAmount` of `stableAssetId` (the cash backing\n//     for buying BTC at strike if the buyer exercises).\n//   - Buyer locks NOTHING upfront. The BTC delivery to the seller's\n//     address happens only IF the buyer chooses to exercise.\n//   - Premium flows MM->seller off-contract in the funding transaction.\n//\n// Exercise at the buyer's option:\n//   - In `[expiryHeight, expiryHeight + graceBlocks)`, the buyer may\n//     exercise by submitting a transaction that delivers `btcSats` BTC\n//     to the seller and takes the `stableAmount` stablecoin.\n//   - A rational buyer exercises iff in-the-money (spot < strike); if\n//     out-of-the-money they walk away, forfeiting only the premium.\n//   - If the buyer doesn't exercise within the grace window, the seller\n//     reclaims the cash via `reclaim()`. Buyer's failure to exercise =\n//     seller keeps the stable for free at the cost of one premium already\n//     received.\n//\n// No oracle. Buyer's exercise decision is the settlement signal.\n//\n// Transaction layout for exercise:\n//   input[0]:   this CashSecuredPut UTXO   (stableAmount of stableAssetId)\n//   input[1+]:  buyer's BTC inputs         (>= btcSats + buyer's BTC fee)\n//   output[0]:  seller receives BTC       (btcSats BTC, locked to sellerPk)\n//   output[1]:  buyer receives stable      (stableAmount of stableAssetId, locked to buyerPk)\n//   output[2+]: buyer's BTC change         (unconstrained)\n//\n// Transfer functions allow either party to reassign their leg before\n// expiry. The vault holds only the stablecoin, so the continuation\n// output preserves the stablecoin asset balance (not BTC value).\n\nimport \"single_sig.ark\";\n\noptions {\n  server = server;\n  exit = exit;\n}\n\ncontract CashSecuredPut(\n  pubkey  sellerPk,         // option writer; locks the stable\n  pubkey  buyerPk,          // option holder\n  bytes32 stableAssetId,    // USDT / USDC asset id\n  int     stableAmount,     // seller's deposit (strike value)\n  int     btcSats,          // BTC the buyer must deliver to exercise\n  int     expiryHeight,     // exercise window opens at this block height\n  int     graceBlocks,      // length of the exercise window in blocks\n  int     exit              // exit timelock in blocks\n) {\n\n  // -------------------------------------------------------------------------\n  // EXERCISE\n  // Buyer exercises by delivering `btcSats` BTC to the seller and taking\n  // the locked stablecoin.\n  // -------------------------------------------------------------------------\n  function exercise(signature buyerSig) {\n    require(tx.time >= expiryHeight, \"before expiry\");\n    require(checkSig(buyerSig, buyerPk), \"invalid buyer sig\");\n\n    // Output 0: seller receives the BTC.\n    require(tx.outputs[0].value >= btcSats, \"seller underpaid\");\n    require(\n      tx.outputs[0].scriptPubKey == new SingleSig(sellerPk),\n      \"output 0 not seller\"\n    );\n\n    // Output 1: buyer receives the stablecoin.\n    require(\n      tx.outputs[1].assets.lookup(stableAssetId) >= stableAmount,\n      \"buyer underpaid\"\n    );\n    require(\n      tx.outputs[1].scriptPubKey == new SingleSig(buyerPk),\n      \"output 1 not buyer\"\n    );\n  }\n\n  // -------------------------------------------------------------------------\n  // RECLAIM\n  // Seller takes the stablecoin back once the grace window closes.\n  // -------------------------------------------------------------------------\n  function reclaim(signature sellerSig) {\n    int reclaimHeight = expiryHeight + graceBlocks;\n    require(tx.time >= reclaimHeight, \"reclaim window not open\");\n    require(checkSig(sellerSig, sellerPk), \"invalid seller sig\");\n  }\n\n  // -------------------------------------------------------------------------\n  // TRANSFER_SELLER\n  // Pre-expiry only. Writer re-assigns the short leg to a new seller.\n  // Stablecoin collateral preserved on the continuation output.\n  // -------------------------------------------------------------------------\n  function transferSeller(signature sellerSig, pubkey newSellerPk) {\n    require(tx.time < expiryHeight, \"no transfers after expiry\");\n    require(checkSig(sellerSig, sellerPk), \"invalid seller sig\");\n    require(\n      tx.outputs[0].scriptPubKey == new CashSecuredPut(\n        newSellerPk, buyerPk, stableAssetId,\n        stableAmount, btcSats, expiryHeight, graceBlocks, exit\n      ),\n      \"invalid transfer output\"\n    );\n    require(\n      tx.outputs[0].assets.lookup(stableAssetId) >= stableAmount,\n      \"collateral not preserved\"\n    );\n  }\n\n  // -------------------------------------------------------------------------\n  // TRANSFER_BUYER\n  // Pre-expiry only. Holder re-assigns the long leg to a new buyer.\n  // Stablecoin collateral preserved on the continuation output.\n  // -------------------------------------------------------------------------\n  function transferBuyer(signature buyerSig, pubkey newBuyerPk) {\n    require(tx.time < expiryHeight, \"no transfers after expiry\");\n    require(checkSig(buyerSig, buyerPk), \"invalid buyer sig\");\n    require(\n      tx.outputs[0].scriptPubKey == new CashSecuredPut(\n        sellerPk, newBuyerPk, stableAssetId,\n        stableAmount, btcSats, expiryHeight, graceBlocks, exit\n      ),\n      \"invalid transfer output\"\n    );\n    require(\n      tx.outputs[0].assets.lookup(stableAssetId) >= stableAmount,\n      \"collateral not preserved\"\n    );\n  }\n}\n";

export const covered_call = "// CoveredCall Contract\n//\n// Bitcoin-native, single-locked, physically-settled European covered\n// call. Faithful match to Rysk Finance v12:\n//   https://docs.rysk.finance/getting-started/protocol-and-product/how-it-works\n//\n// Single-sided collateral lockup:\n//   - Seller locks `btcSats` of BTC.\n//   - Buyer locks NOTHING upfront. The strike payment in stablecoin is\n//     transferred to the seller's address only IF the buyer chooses to\n//     exercise at expiry.\n//   - Premium flows MM->seller off-contract in the funding transaction.\n//\n// Exercise at the buyer's option:\n//   - In `[expiryHeight, expiryHeight + graceBlocks)`, the buyer may\n//     exercise by submitting a transaction that pays `strikeAmount` of\n//     `stableAssetId` to the seller and takes `btcSats` BTC.\n//   - A rational buyer exercises iff in-the-money (spot > strike); if\n//     out-of-the-money they walk away, forfeiting only the premium they\n//     already paid at funding.\n//   - If the buyer doesn't exercise within the grace window (including\n//     the case where they should have but didn't), the seller reclaims\n//     the BTC via `reclaim()`. Buyer's failure to exercise = seller\n//     keeps the BTC for free at the cost of one premium they already\n//     received.\n//\n// This is the MM-friendly capital model: the option writer doesn't tie\n// up the strike value of every option they write — they only need to\n// have stablecoin liquidity at exercise time. Capital efficiency is the\n// reason Rysk's RFQ counterparties can quote at scale.\n//\n// No oracle. The buyer's exercise decision IS the settlement signal.\n//\n// Transaction layout for exercise:\n//   input[0]:   this CoveredCall UTXO    (btcSats BTC)\n//   input[1+]:  buyer's stablecoin inputs  (>= strikeAmount + buyer's BTC fee)\n//   output[0]:  seller receives strike    (strikeAmount of stableAssetId, locked to sellerPk)\n//   output[1]:  buyer receives BTC        (btcSats BTC, locked to buyerPk)\n//   output[2+]: buyer's stablecoin change (unconstrained)\n//\n// Transfer functions allow either party to reassign their leg before\n// expiry. The vault holds only BTC, so the continuation output preserves\n// just the BTC value.\n\nimport \"single_sig.ark\";\n\noptions {\n  server = server;\n  exit = exit;\n}\n\ncontract CoveredCall(\n  pubkey  sellerPk,         // option writer; locks the BTC\n  pubkey  buyerPk,          // option holder\n  bytes32 stableAssetId,    // USDT / USDC asset id\n  int     btcSats,          // seller's deposit\n  int     strikeAmount,     // total stablecoin the buyer must pay to exercise\n  int     expiryHeight,     // exercise window opens at this block height\n  int     graceBlocks,      // length of the exercise window in blocks\n  int     exit              // exit timelock in blocks\n) {\n\n  // -------------------------------------------------------------------------\n  // EXERCISE\n  // Buyer exercises by paying `strikeAmount` of `stableAssetId` to seller\n  // and receiving the locked BTC. Valid from `expiryHeight` onward; in\n  // practice the buyer should broadcast within `graceBlocks` because once\n  // the reclaim path matures, the seller races them and wins by default.\n  // -------------------------------------------------------------------------\n  function exercise(signature buyerSig) {\n    require(tx.time >= expiryHeight, \"before expiry\");\n    require(checkSig(buyerSig, buyerPk), \"invalid buyer sig\");\n\n    // Output 0: seller receives the strike payment in stablecoin.\n    require(\n      tx.outputs[0].assets.lookup(stableAssetId) >= strikeAmount,\n      \"seller underpaid\"\n    );\n    require(\n      tx.outputs[0].scriptPubKey == new SingleSig(sellerPk),\n      \"output 0 not seller\"\n    );\n\n    // Output 1: buyer receives the BTC collateral.\n    require(tx.outputs[1].value >= btcSats, \"buyer underpaid\");\n    require(\n      tx.outputs[1].scriptPubKey == new SingleSig(buyerPk),\n      \"output 1 not buyer\"\n    );\n  }\n\n  // -------------------------------------------------------------------------\n  // RECLAIM\n  // Seller takes the BTC back once the grace window closes. After this\n  // block, the seller and the buyer's exercise tx are in a race — the\n  // first to confirm wins. A rational buyer who hasn't exercised by now\n  // has chosen not to (likely OTM); seller broadcasts immediately at\n  // reclaimHeight.\n  // -------------------------------------------------------------------------\n  function reclaim(signature sellerSig) {\n    int reclaimHeight = expiryHeight + graceBlocks;\n    require(tx.time >= reclaimHeight, \"reclaim window not open\");\n    require(checkSig(sellerSig, sellerPk), \"invalid seller sig\");\n  }\n\n  // -------------------------------------------------------------------------\n  // TRANSFER_SELLER\n  // Pre-expiry only. Writer re-assigns the short leg to a new seller.\n  // BTC collateral preserved on the continuation output.\n  // -------------------------------------------------------------------------\n  function transferSeller(signature sellerSig, pubkey newSellerPk) {\n    require(tx.time < expiryHeight, \"no transfers after expiry\");\n    require(checkSig(sellerSig, sellerPk), \"invalid seller sig\");\n    require(\n      tx.outputs[0].scriptPubKey == new CoveredCall(\n        newSellerPk, buyerPk, stableAssetId,\n        btcSats, strikeAmount, expiryHeight, graceBlocks, exit\n      ),\n      \"invalid transfer output\"\n    );\n    require(tx.outputs[0].value >= btcSats, \"collateral not preserved\");\n  }\n\n  // -------------------------------------------------------------------------\n  // TRANSFER_BUYER\n  // Pre-expiry only. Holder re-assigns the long leg to a new buyer.\n  // BTC collateral preserved on the continuation output.\n  // -------------------------------------------------------------------------\n  function transferBuyer(signature buyerSig, pubkey newBuyerPk) {\n    require(tx.time < expiryHeight, \"no transfers after expiry\");\n    require(checkSig(buyerSig, buyerPk), \"invalid buyer sig\");\n    require(\n      tx.outputs[0].scriptPubKey == new CoveredCall(\n        sellerPk, newBuyerPk, stableAssetId,\n        btcSats, strikeAmount, expiryHeight, graceBlocks, exit\n      ),\n      \"invalid transfer output\"\n    );\n    require(tx.outputs[0].value >= btcSats, \"collateral not preserved\");\n  }\n}\n";

export const payment_auth = "// Payment Authorization Contract\n// Authorization-based escrow with timelocked refunds using transaction introspection\n//\n// This contract implements a credit card-like payment flow:\n// 1. Customer locks funds in escrow\n// 2. Merchant can capture (authorize and settle) the payment\n// 3. If not captured, customer can refund after timelock expires\n//\n// The contract validates the full payout structure:\n// - Merchant receives payment minus processor fee\n// - Processor receives fee (basis points of payment)\n// - Customer receives change if overpayment\n\noptions {\n  server = server;\n  exit = 144;\n}\n\ncontract PaymentAuthorization(\n  // Server key for cooperative path\n  pubkey server,\n\n  // Payment terms\n  int invoiceAmount,\n  int feeRateBasisPoints,\n\n  // Output scripts (P2TR scriptPubKeys)\n  bytes merchantScript,\n  bytes processorScript,\n  bytes customerScript,\n\n  // Refund timelock (block height)\n  int refundBlockHeight,\n\n  // Authorization key\n  pubkey merchantPubkey\n) {\n\n  // Capture: merchant-authorized settlement\n  // Validates payout structure based on payment amount vs invoice\n  function capture(signature merchantSig) {\n    require(checkSig(merchantSig, merchantPubkey), \"Invalid merchant signature\");\n\n    // Get the current input value (amount locked in escrow)\n    let vtxoValue = tx.input.current.value;\n\n    // Case 1: Underpayment (vtxoValue < invoiceAmount)\n    // Pay merchant (minus fee) + processor fee\n    if (vtxoValue < invoiceAmount) {\n      require(vtxoValue >= 10000, \"Payment below dust threshold\");\n      require(tx.numOutputs == 2, \"Expected 2 outputs for underpayment\");\n\n      // Fee = vtxoValue * feeRateBasisPoints / 10000\n      let processorFee = (vtxoValue * feeRateBasisPoints) / 10000;\n      let merchantAmount = vtxoValue - processorFee;\n\n      require(tx.outputs[0].value == merchantAmount, \"Merchant amount incorrect\");\n      require(tx.outputs[0].scriptPubKey == merchantScript, \"Merchant script incorrect\");\n\n      require(tx.outputs[1].value == processorFee, \"Processor fee incorrect\");\n      require(tx.outputs[1].scriptPubKey == processorScript, \"Processor script incorrect\");\n    }\n\n    // Case 2: Exact payment (vtxoValue == invoiceAmount)\n    // Pay merchant (minus fee) + processor fee\n    if (vtxoValue == invoiceAmount) {\n      require(tx.numOutputs == 2, \"Expected 2 outputs for exact payment\");\n\n      // Fee = invoiceAmount * feeRateBasisPoints / 10000\n      let processorFee = (invoiceAmount * feeRateBasisPoints) / 10000;\n      let merchantAmount = invoiceAmount - processorFee;\n\n      require(tx.outputs[0].value == merchantAmount, \"Merchant amount incorrect\");\n      require(tx.outputs[0].scriptPubKey == merchantScript, \"Merchant script incorrect\");\n\n      require(tx.outputs[1].value == processorFee, \"Processor fee incorrect\");\n      require(tx.outputs[1].scriptPubKey == processorScript, \"Processor script incorrect\");\n    }\n\n    // Case 3: Overpayment (vtxoValue > invoiceAmount)\n    // Pay merchant (minus fee) + processor fee + customer change\n    if (vtxoValue > invoiceAmount) {\n      require(tx.numOutputs == 3, \"Expected 3 outputs for overpayment\");\n\n      // Fee = invoiceAmount * feeRateBasisPoints / 10000\n      let processorFee = (invoiceAmount * feeRateBasisPoints) / 10000;\n      let merchantAmount = invoiceAmount - processorFee;\n      let changeAmount = vtxoValue - invoiceAmount;\n\n      require(tx.outputs[0].value == merchantAmount, \"Merchant amount incorrect\");\n      require(tx.outputs[0].scriptPubKey == merchantScript, \"Merchant script incorrect\");\n\n      require(tx.outputs[1].value == processorFee, \"Processor fee incorrect\");\n      require(tx.outputs[1].scriptPubKey == processorScript, \"Processor script incorrect\");\n\n      require(tx.outputs[2].value == changeAmount, \"Change amount incorrect\");\n      require(tx.outputs[2].scriptPubKey == customerScript, \"Change script incorrect\");\n    }\n  }\n\n  // Refund: timelocked fallback back to customer\n  // Becomes valid after refundBlockHeight - effectively anyone-can-spend into customerScript\n  function refund() {\n    require(tx.time >= refundBlockHeight, \"Refund timelock not reached\");\n\n    let vtxoValue = tx.input.current.value;\n\n    require(tx.numOutputs == 1, \"Expected 1 output for refund\");\n    require(tx.outputs[0].value == vtxoValue, \"Refund amount incorrect\");\n    require(tx.outputs[0].scriptPubKey == customerScript, \"Refund script incorrect\");\n  }\n}\n";

export const single_sig = "// Contract configuration options\noptions {\n  // Server key \n  server = server;\n  \n  // Renewal timelock: 7 days (1008 blocks)\n  // The contract must be renewed with the Arkade server within this period\n  renew = 1008;\n  \n  // Exit timelock: 24 hours (144 blocks)\n  // Time required to exit unilaterally without server involvement\n  exit = 144;\n}\n\ncontract SingleSig(\n  pubkey user\n) {\n  // Single signature spend path\n  // This will automatically be compiled into:\n  // 1. Cooperative path: checkSig(user) && checkSig(server)\n  // 2. Exit path: checkSig(user) && after 144 blocks\n  function spend(signature userSig) {\n    require(checkSig(userSig, user));\n  }\n} ";

export const stability_offer = "// StabilityOffer Contract\n//\n// Provider pre-commits BTC liquidity into a standing offer.\n// Any swap service (or direct Seeker) can claim it non-interactively by\n// supplying a fresh oracle-signed price.\n//\n// Flow:\n//   1. Provider deploys StabilityOffer with their BTC collateral.\n//   2. Taker calls take(userBTC, seekerPk, oraclePrice, oracleTime, oracleSig).\n//   3. Contract verifies the oracle signature over sha256(ticker||price||time),\n//      enforces freshness, charges takeFee to the provider, and opens a\n//      StabilityVault bound to this ticker.\n//   4. Provider calls withdraw() to reclaim unused collateral at any time.\n//\n// Fees committed at offer creation (immutable across takes), expressed in\n// basis points (1e4 scale: 100 = 1%):\n//   - takeFee:        takeFee × userBTC / 1e4 sats; rolled into the vault\n//                     when below the 330-sat dust threshold (provider\n//                     reclaims it on their exit), otherwise emitted as a\n//                     separate output.\n//   - seekerExitFee:  applied in USD as (1 − seekerExitFee/1e4) × newTargetUSD\n//                     when seekerExit settles. Propagates into every vault.\n\nimport \"stability_vault.ark\";\n\noptions {\n  server = server;\n  exit = exit;\n}\n\ncontract StabilityOffer(\n  pubkey  providerPk,\n  pubkey  oraclePk,\n  bytes32 ticker,              // feed identifier; propagates into every vault\n  int     fundingRatePerSec,   // signed fixed-point at scale 1e12; seeker accepts this rate on take\n  int     maxExposureBTC,\n  int     collateralRatioPct,  // min 100 logically; offer guards 50%+ here\n  int     seekerExitFee,       // basis points; propagated into every vault\n  int     takeFee,             // basis points; takeFee × userBTC / 1e4 sats paid to provider on take\n  int     exit\n) {\n\n  // -------------------------------------------------------------------------\n  // TAKE\n  // Non-interactive: no provider signature.\n  // Caller supplies oracle-signed price; contract verifies the full message,\n  // charges takeFee, and opens a StabilityVault at the attested price.\n  //\n  // Transaction layout:\n  //   input[0]:  this StabilityOffer UTXO\n  //   input[1]:  taker's BTC (userBTC sats)\n  //   output[0]: StabilityVault\n  //   output[1]: takeFee → provider           (only if takeFee > 330)\n  //   output[2]: remaining StabilityOffer     (only if partial fill)\n  // -------------------------------------------------------------------------\n  function take(\n    int       userBTC,\n    pubkey    seekerPk,\n    int       oraclePrice,\n    int       oracleTime,\n    signature oracleSig\n  ) {\n    require(userBTC > 0, \"zero deposit\");\n    require(userBTC <= maxExposureBTC, \"exceeds offer capacity\");\n    require(collateralRatioPct >= 100, \"collateral ratio below minimum\");\n    require(oraclePrice > 0, \"invalid oracle price\");\n    require(seekerExitFee >= 0, \"negative exit fee\");\n    require(seekerExitFee <= 10000, \"exit fee > 100%\");\n    require(takeFee >= 0, \"negative take fee\");\n    require(takeFee <= 10000, \"take fee > 100%\");\n\n    int oracleAge = tx.offchainTime - oracleTime;\n    require(oracleAge >= 0, \"future-dated oracle\");\n    require(oracleAge <= 600, \"stale oracle\");\n\n    let oracleMsg = sha256(ticker + oraclePrice + oracleTime);\n    require(checkSigFromStack(oracleSig, oraclePk, oracleMsg), \"invalid oracle signature\");\n\n    int targetUSD = userBTC * oraclePrice / 100000000;\n    require(targetUSD > 0, \"position too small\");\n\n    int totalCollateral       = userBTC * (100 + collateralRatioPct) / 100;\n    int takeFeeSats           = userBTC * takeFee / 10000;\n    int remainingCapacity     = maxExposureBTC - userBTC;\n    int remainingCollateral   = remainingCapacity * collateralRatioPct / 100;\n\n    // takeFeeSats > 330  → fee is its own output (output[1]); remaining offer\n    //                       (if any) goes at output[2].\n    // takeFeeSats ≤ 330  → fee is rolled into the vault output (provider\n    //                       reclaims it on exit since vault.value > totalCollateral\n    //                       always flows to provider). Remaining offer at output[1].\n    if (takeFeeSats > 330) {\n      require(\n        tx.outputs[0].scriptPubKey == new StabilityVault(\n          seekerPk, providerPk, oraclePk, ticker,\n          targetUSD, totalCollateral, fundingRatePerSec, tx.offchainTime,\n          collateralRatioPct, seekerExitFee, exit\n        ),\n        \"invalid vault output\"\n      );\n      require(tx.outputs[0].value >= totalCollateral, \"insufficient vault collateral\");\n      require(tx.outputs[1].scriptPubKey == new SingleSig(providerPk), \"output 1 not provider\");\n      require(tx.outputs[1].value >= takeFeeSats, \"provider underpaid take fee\");\n      if (remainingCapacity > 0) {\n        require(\n          tx.outputs[2].scriptPubKey == new StabilityOffer(\n            providerPk, oraclePk, ticker,\n            fundingRatePerSec, remainingCapacity, collateralRatioPct,\n            seekerExitFee, takeFee, exit\n          ),\n          \"invalid remaining offer\"\n        );\n        require(tx.outputs[2].value >= remainingCollateral, \"insufficient offer collateral\");\n      }\n    } else {\n      // Dust fee rolled into the vault — vault collects totalCollateral + takeFeeSats.\n      require(\n        tx.outputs[0].scriptPubKey == new StabilityVault(\n          seekerPk, providerPk, oraclePk, ticker,\n          targetUSD, totalCollateral, fundingRatePerSec, tx.offchainTime,\n          collateralRatioPct, seekerExitFee, exit\n        ),\n        \"invalid vault output\"\n      );\n      int dustVaultValue = totalCollateral + takeFeeSats;\n      require(tx.outputs[0].value >= dustVaultValue, \"insufficient vault collateral\");\n      if (remainingCapacity > 0) {\n        require(\n          tx.outputs[1].scriptPubKey == new StabilityOffer(\n            providerPk, oraclePk, ticker,\n            fundingRatePerSec, remainingCapacity, collateralRatioPct,\n            seekerExitFee, takeFee, exit\n          ),\n          \"invalid remaining offer\"\n        );\n        require(tx.outputs[1].value >= remainingCollateral, \"insufficient offer collateral\");\n      }\n    }\n  }\n\n  // -------------------------------------------------------------------------\n  // WITHDRAW — Provider reclaims unclaimed collateral from the offer.\n  // -------------------------------------------------------------------------\n  function withdraw(signature providerSig) {\n    require(checkSig(providerSig, providerPk), \"invalid provider sig\");\n  }\n}\n";

export const stability_vault = "// StabilityVault Contract\n//\n// A USD-denominated claim backed by BTC collateral.\n// Seeker holds a fixed USD value; Provider locks additional collateral and\n// takes a leveraged BTC long. Provider pays Seeker a funding rate.\n//\n// Funding model (USD-compound):\n//   At every settlement boundary the USD claim is rolled forward:\n//     elapsed       = tx.offchainTime - lastUpdate\n//     newTargetUSD  = targetUSD × (1 + fundingRatePerSec × elapsed / 1e12)\n//   targetUSD compounds in USD terms. fundingRatePerSec is a signed\n//   fixed-point fraction at scale 1e12.\n//\n// Settlement math (single shape across settleAndUpdateFunding,\n// seekerExit, providerExit, removeCapital):\n//   newTargetUSD = targetUSD × (1 + fundingRatePerSec × elapsed / 1e12)\n//   seekerRaw    = newTargetUSD × (1 - seekerExitFee/1e4) × 1e8 / P   [seekerExit]\n//   seekerRaw    = newTargetUSD × 1e8 / P                              [providerExit]\n//   seekerPayout = clamp(seekerRaw, 0, totalCollateral)\n//   providerPayout = totalCollateral − seekerPayout\n//\n// seekerExitFee is a basis-point fraction (1e4 scale): 100 = 1%, 10000 = 100%.\n// It applies in USD terms, before conversion to sats — so the fee scales\n// with position size and matches the % shape of fundingRatePerSec.\n//\n// Oracle model (Fuji-style signed price feed):\n//   Oracle off-chain produces:\n//     msg = sha256(ticker || price || timestamp)\n//     sig = sign(oraclePk, msg)\n//   where price and timestamp are 8-byte little-endian unsigned ints.\n//   At settlement the caller supplies (oraclePrice, oracleTime, oracleSig).\n//   Freshness: tx.offchainTime - oracleTime <= 600 seconds.\n//\n//   `tx.offchainTime` is the TEE-introspector wallclock (unix seconds),\n//   distinct from `tx.time` (Bitcoin nLockTime, block height).\n//\n// Three pieces of oracle replay protection are baked into the message:\n//   - ticker     → binds the signature to this feed\n//   - price      → the value being attested\n//   - timestamp  → unique per update; combined with the freshness window,\n//                  stale signatures are rejected.\n\nimport \"single_sig.ark\";\n\noptions {\n  server = server;\n  exit = exit;\n}\n\ncontract StabilityVault(\n  pubkey  seekerPk,           // current holder of the USD claim\n  pubkey  providerPk,         // collateral provider, holds the long side\n  pubkey  oraclePk,           // only signatures from this key accepted\n  bytes32 ticker,             // feed identifier (e.g. sha256(\"BTC/USD\"))\n  int     targetUSD,          // seeker's USD claim in cents; mutates on settle\n  int     totalCollateral,    // sats locked; mutates on add/removeCapital\n  int     fundingRatePerSec,  // signed fixed-point at scale 1e12; mutates on settle\n  int     lastUpdate,         // unix seconds; basis for funding accrual\n  int     collateralRatioPct, // min collateral ratio for removeCapital (e.g. 50 = 1.5:1)\n  int     seekerExitFee,      // basis points (1e4 scale); seekerExit pays fee × targetUSD to provider\n  int     exit                // exit timelock in blocks\n) {\n\n  // -------------------------------------------------------------------------\n  // TRANSFER — pure key swap, no oracle.\n  // -------------------------------------------------------------------------\n  function transfer(signature seekerSig, pubkey newSeekerPk) {\n    require(checkSig(seekerSig, seekerPk), \"invalid seeker sig\");\n\n    require(\n      tx.outputs[0].scriptPubKey == new StabilityVault(\n        newSeekerPk, providerPk, oraclePk, ticker,\n        targetUSD, totalCollateral, fundingRatePerSec, lastUpdate,\n        collateralRatioPct, seekerExitFee, exit\n      ),\n      \"invalid transfer output\"\n    );\n    require(tx.outputs[0].value >= totalCollateral, \"collateral not preserved\");\n  }\n\n  // -------------------------------------------------------------------------\n  // SPLIT — proportional USD-claim split into two independent positions.\n  // -------------------------------------------------------------------------\n  function split(signature seekerSig, int amountUSD, pubkey newSeekerPk) {\n    require(checkSig(seekerSig, seekerPk), \"invalid seeker sig\");\n    require(amountUSD > 0, \"zero amount\");\n    require(amountUSD < targetUSD, \"amount exceeds balance\");\n\n    int remainingUSD = targetUSD - amountUSD;\n    int collateralA  = totalCollateral * amountUSD / targetUSD;\n    int collateralB  = totalCollateral - collateralA;\n\n    require(collateralA >= 330, \"split amount too small\");\n    require(collateralB >= 330, \"remainder too small\");\n\n    require(\n      tx.outputs[0].scriptPubKey == new StabilityVault(\n        newSeekerPk, providerPk, oraclePk, ticker,\n        amountUSD, collateralA, fundingRatePerSec, lastUpdate,\n        collateralRatioPct, seekerExitFee, exit\n      ),\n      \"invalid split output 0\"\n    );\n    require(tx.outputs[0].value >= collateralA, \"insufficient collateral A\");\n\n    require(\n      tx.outputs[1].scriptPubKey == new StabilityVault(\n        seekerPk, providerPk, oraclePk, ticker,\n        remainingUSD, collateralB, fundingRatePerSec, lastUpdate,\n        collateralRatioPct, seekerExitFee, exit\n      ),\n      \"invalid split output 1\"\n    );\n    require(tx.outputs[1].value >= collateralB, \"insufficient collateral B\");\n  }\n\n  // -------------------------------------------------------------------------\n  // MERGE — Seeker combines two of their own vaults into one.\n  //\n  // Both vaults must share: seekerPk, providerPk, oraclePk, ticker,\n  // collateralRatioPct, exit. They may differ on targetUSD, totalCollateral,\n  // fundingRatePerSec, lastUpdate, seekerExitFee.\n  //\n  // Merged values:\n  //   - targetUSD          = accruedA + accruedB  (funding rolled in per side)\n  //   - totalCollateral    = totalCollateralA + totalCollateralB\n  //   - fundingRatePerSec  = max(rateA, rateB)         — provider's higher rate wins\n  //   - lastUpdate         = tx.offchainTime\n  //   - seekerExitFee      = max(exitFeeA, exitFeeB)   — higher exit fee wins\n  //\n  // Position-agnostic: this script runs on both spent vaults. `otherIdx` is a\n  // witness pointing to the OTHER vault input; activeInputIndex distinguishes\n  // self from sibling. Both scripts agree on the merged output by symmetry\n  // (sum and max are commutative), so output[0] passes in both verifications.\n  // -------------------------------------------------------------------------\n  function merge(\n    signature seekerSig,\n    int       otherIdx,\n    int       otherTargetUSD,\n    int       otherTotalCollateral,\n    int       otherFundingRatePerSec,\n    int       otherLastUpdate,\n    int       otherSeekerExitFee,\n    int       mergedFundingRatePerSec,\n    int       mergedSeekerExitFee\n  ) {\n    require(checkSig(seekerSig, seekerPk), \"invalid seeker sig\");\n    require(this.activeInputIndex != otherIdx, \"self-merge disallowed\");\n\n    // The other input must be a sibling vault: same seeker, provider, oracle,\n    // ticker, collateralRatioPct, exit; only state fields may differ.\n    require(\n      tx.inputs[otherIdx].scriptPubKey == new StabilityVault(\n        seekerPk, providerPk, oraclePk, ticker,\n        otherTargetUSD, otherTotalCollateral, otherFundingRatePerSec, otherLastUpdate,\n        collateralRatioPct, otherSeekerExitFee, exit\n      ),\n      \"input not matching vault\"\n    );\n\n    // Enforce mergedFundingRatePerSec = max(this, other).\n    if (fundingRatePerSec >= otherFundingRatePerSec) {\n      require(mergedFundingRatePerSec == fundingRatePerSec, \"merged rate != max\");\n    } else {\n      require(mergedFundingRatePerSec == otherFundingRatePerSec, \"merged rate != max\");\n    }\n\n    // Enforce mergedSeekerExitFee = max(this, other).\n    if (seekerExitFee >= otherSeekerExitFee) {\n      require(mergedSeekerExitFee == seekerExitFee, \"merged exit fee != max\");\n    } else {\n      require(mergedSeekerExitFee == otherSeekerExitFee, \"merged exit fee != max\");\n    }\n\n    // Accrue funding on each side at its own rate before summing.\n    int elapsedA      = tx.offchainTime - lastUpdate;\n    require(elapsedA >= 0, \"clock regression A\");\n    int rateElapsedA  = fundingRatePerSec * elapsedA / 1000000;\n    int deltaA        = targetUSD * rateElapsedA / 1000000;\n    int accruedA      = targetUSD + deltaA;\n\n    int elapsedB      = tx.offchainTime - otherLastUpdate;\n    require(elapsedB >= 0, \"clock regression B\");\n    int rateElapsedB  = otherFundingRatePerSec * elapsedB / 1000000;\n    int deltaB        = otherTargetUSD * rateElapsedB / 1000000;\n    int accruedB      = otherTargetUSD + deltaB;\n\n    int mergedTargetUSD       = accruedA + accruedB;\n    int mergedTotalCollateral = totalCollateral + otherTotalCollateral;\n\n    require(\n      tx.outputs[0].scriptPubKey == new StabilityVault(\n        seekerPk, providerPk, oraclePk, ticker,\n        mergedTargetUSD, mergedTotalCollateral, mergedFundingRatePerSec, tx.offchainTime,\n        collateralRatioPct, mergedSeekerExitFee, exit\n      ),\n      \"invalid merged vault output\"\n    );\n    require(tx.outputs[0].value >= mergedTotalCollateral, \"merged collateral underfunded\");\n  }\n\n  // -------------------------------------------------------------------------\n  // SETTLE & UPDATE FUNDING\n  // Provider rolls accrued funding into targetUSD and sets a new rate.\n  // newFundingRatePerSec must be >= 0: a negative rate would let the Provider\n  // unilaterally drain the Seeker. The Seeker's consent at offer-accept time\n  // is the only point where a negative initial rate is allowed.\n  //\n  // Worst case for the Seeker: Provider sets rate to 0, suspending further\n  // interest. They can react by calling seekerExit.\n  // -------------------------------------------------------------------------\n  function settleAndUpdateFunding(signature providerSig, int newFundingRatePerSec) {\n    require(checkSig(providerSig, providerPk), \"invalid provider sig\");\n    require(newFundingRatePerSec >= 0, \"negative funding rate disallowed\");\n\n    int elapsed           = tx.offchainTime - lastUpdate;\n    require(elapsed >= 0, \"clock regression\");\n    int rateElapsedScaled = fundingRatePerSec * elapsed / 1000000;\n    int delta             = targetUSD * rateElapsedScaled / 1000000;\n    int newTargetUSD      = targetUSD + delta;\n    require(newTargetUSD > 0, \"claim wiped by funding\");\n\n    // Anti-grief: if rate > 0 and delta truncates to 0, provider would be\n    // calling settle with no accrual while advancing lastUpdate, which\n    // suppresses funding owed to the seeker. Allow no-accrual settles only\n    // when current rate is already 0 (legitimate \"resume from pause\").\n    if (fundingRatePerSec != 0) {\n      require(delta > 0, \"no accrual; wait longer\");\n    }\n\n    require(\n      tx.outputs[0].scriptPubKey == new StabilityVault(\n        seekerPk, providerPk, oraclePk, ticker,\n        newTargetUSD, totalCollateral, newFundingRatePerSec, tx.offchainTime,\n        collateralRatioPct, seekerExitFee, exit\n      ),\n      \"invalid settle output\"\n    );\n    require(tx.outputs[0].value >= totalCollateral, \"collateral not preserved\");\n  }\n\n  // -------------------------------------------------------------------------\n  // ADD CAPITAL — Provider tops up collateral. No ratio check needed (more\n  // collateral is always strictly better for the Seeker).\n  // -------------------------------------------------------------------------\n  function addCapital(signature providerSig, int amount) {\n    require(checkSig(providerSig, providerPk), \"invalid provider sig\");\n    require(amount > 0, \"zero amount\");\n\n    int newTotalCollateral = totalCollateral + amount;\n\n    require(\n      tx.outputs[0].scriptPubKey == new StabilityVault(\n        seekerPk, providerPk, oraclePk, ticker,\n        targetUSD, newTotalCollateral, fundingRatePerSec, lastUpdate,\n        collateralRatioPct, seekerExitFee, exit\n      ),\n      \"invalid output\"\n    );\n    require(tx.outputs[0].value >= newTotalCollateral, \"collateral not deposited\");\n  }\n\n  // -------------------------------------------------------------------------\n  // REMOVE CAPITAL — Provider reclaims excess collateral, but the remaining\n  // position must still cover seekerBase at the offer's collateral ratio.\n  // Funding accrued to-date is included in the check (without rolling it into\n  // the vault — provider can call settleAndUpdateFunding first if desired).\n  // -------------------------------------------------------------------------\n  function removeCapital(\n    signature providerSig,\n    int       amount,\n    int       oraclePrice,\n    int       oracleTime,\n    signature oracleSig\n  ) {\n    require(checkSig(providerSig, providerPk), \"invalid provider sig\");\n    require(amount > 0, \"zero amount\");\n    require(oraclePrice > 0, \"invalid oracle price\");\n\n    int oracleAge = tx.offchainTime - oracleTime;\n    require(oracleAge >= 0, \"future-dated oracle\");\n    require(oracleAge <= 600, \"stale oracle\");\n\n    let oracleMsg = sha256(ticker + oraclePrice + oracleTime);\n    require(checkSigFromStack(oracleSig, oraclePk, oracleMsg), \"invalid oracle signature\");\n\n    int elapsed           = tx.offchainTime - lastUpdate;\n    require(elapsed >= 0, \"clock regression\");\n    int rateElapsedScaled = fundingRatePerSec * elapsed / 1000000;\n    int delta             = targetUSD * rateElapsedScaled / 1000000;\n    int newTargetUSD      = targetUSD + delta;\n    int currentSeekerBase = newTargetUSD * 100000000 / oraclePrice;\n    int minCollateral     = currentSeekerBase * (100 + collateralRatioPct) / 100;\n    int newTotalCollateral = totalCollateral - amount;\n    require(newTotalCollateral >= minCollateral, \"would breach collateral ratio\");\n\n    require(\n      tx.outputs[0].scriptPubKey == new StabilityVault(\n        seekerPk, providerPk, oraclePk, ticker,\n        targetUSD, newTotalCollateral, fundingRatePerSec, lastUpdate,\n        collateralRatioPct, seekerExitFee, exit\n      ),\n      \"invalid vault output\"\n    );\n    require(tx.outputs[0].value >= newTotalCollateral, \"vault underfunded\");\n    require(tx.outputs[1].scriptPubKey == new SingleSig(providerPk), \"output 1 not provider\");\n    require(tx.outputs[1].value >= amount, \"provider underpaid\");\n  }\n\n  // -------------------------------------------------------------------------\n  // SEEKER EXIT — Seeker exits to BTC at the oracle-attested price.\n  // Pays seekerExitFee out of own payout to provider (set at offer creation).\n  // -------------------------------------------------------------------------\n  function seekerExit(\n    signature seekerSig,\n    int       oraclePrice,\n    int       oracleTime,\n    signature oracleSig\n  ) {\n    require(checkSig(seekerSig, seekerPk), \"invalid seeker sig\");\n    require(oraclePrice > 0, \"invalid oracle price\");\n\n    int oracleAge = tx.offchainTime - oracleTime;\n    require(oracleAge >= 0, \"future-dated oracle\");\n    require(oracleAge <= 600, \"stale oracle\");\n\n    let oracleMsg = sha256(ticker + oraclePrice + oracleTime);\n    require(checkSigFromStack(oracleSig, oraclePk, oracleMsg), \"invalid oracle signature\");\n\n    // newTargetUSD = targetUSD × (1 + fundingRatePerSec × elapsed / 1e12)\n    // seekerRaw    = newTargetUSD × (1 - seekerExitFee/1e4) × 1e8 / oraclePrice\n    int elapsed           = tx.offchainTime - lastUpdate;\n    require(elapsed >= 0, \"clock regression\");\n    int rateElapsedScaled = fundingRatePerSec * elapsed / 1000000;\n    int delta             = targetUSD * rateElapsedScaled / 1000000;\n    int newTargetUSD      = targetUSD + delta;\n    int netTargetUSD      = newTargetUSD * (10000 - seekerExitFee) / 10000;\n    int seekerRaw         = netTargetUSD * 100000000 / oraclePrice;\n\n    if (seekerRaw <= 0) {\n      require(tx.outputs[0].value >= totalCollateral, \"provider underpaid\");\n      require(tx.outputs[0].scriptPubKey == new SingleSig(providerPk), \"output 0 not provider\");\n    } else {\n      if (seekerRaw >= totalCollateral) {\n        require(tx.outputs[0].value >= totalCollateral, \"seeker underpaid\");\n        require(tx.outputs[0].scriptPubKey == new SingleSig(seekerPk), \"output 0 not seeker\");\n      } else {\n        require(tx.outputs[0].value >= seekerRaw, \"seeker underpaid\");\n        require(tx.outputs[0].scriptPubKey == new SingleSig(seekerPk), \"output 0 not seeker\");\n        int providerPayout = totalCollateral - seekerRaw;\n        if (providerPayout > 330) {\n          require(tx.outputs[1].value >= providerPayout, \"provider underpaid\");\n          require(tx.outputs[1].scriptPubKey == new SingleSig(providerPk), \"output 1 not provider\");\n        }\n      }\n    }\n  }\n\n  // -------------------------------------------------------------------------\n  // PROVIDER EXIT — Identical settlement math; no exit fee charged to provider.\n  // -------------------------------------------------------------------------\n  function providerExit(\n    signature providerSig,\n    int       oraclePrice,\n    int       oracleTime,\n    signature oracleSig\n  ) {\n    require(checkSig(providerSig, providerPk), \"invalid provider sig\");\n    require(oraclePrice > 0, \"invalid oracle price\");\n\n    int oracleAge = tx.offchainTime - oracleTime;\n    require(oracleAge >= 0, \"future-dated oracle\");\n    require(oracleAge <= 600, \"stale oracle\");\n\n    let oracleMsg = sha256(ticker + oraclePrice + oracleTime);\n    require(checkSigFromStack(oracleSig, oraclePk, oracleMsg), \"invalid oracle signature\");\n\n    // newTargetUSD = targetUSD × (1 + fundingRatePerSec × elapsed / 1e12)\n    // seekerRaw    = newTargetUSD × 1e8 / oraclePrice  (no exit fee on provider-driven exit)\n    int elapsed           = tx.offchainTime - lastUpdate;\n    require(elapsed >= 0, \"clock regression\");\n    int rateElapsedScaled = fundingRatePerSec * elapsed / 1000000;\n    int delta             = targetUSD * rateElapsedScaled / 1000000;\n    int newTargetUSD      = targetUSD + delta;\n    int seekerRaw         = newTargetUSD * 100000000 / oraclePrice;\n\n    if (seekerRaw <= 0) {\n      require(tx.outputs[0].value >= totalCollateral, \"provider underpaid\");\n      require(tx.outputs[0].scriptPubKey == new SingleSig(providerPk), \"output 0 not provider\");\n    } else {\n      if (seekerRaw >= totalCollateral) {\n        require(tx.outputs[0].value >= totalCollateral, \"seeker underpaid\");\n        require(tx.outputs[0].scriptPubKey == new SingleSig(seekerPk), \"output 0 not seeker\");\n      } else {\n        require(tx.outputs[0].value >= seekerRaw, \"seeker underpaid\");\n        require(tx.outputs[0].scriptPubKey == new SingleSig(seekerPk), \"output 0 not seeker\");\n        int providerPayout = totalCollateral - seekerRaw;\n        if (providerPayout > 330) {\n          require(tx.outputs[1].value >= providerPayout, \"provider underpaid\");\n          require(tx.outputs[1].scriptPubKey == new SingleSig(providerPk), \"output 1 not provider\");\n        }\n      }\n    }\n  }\n}\n";

export const threshold_multisig_htlc = "// Contract configuration options\noptions {\n  // Server key \n  server = server;\n  \n  // Renewal timelock: 7 days (1008 blocks)\n  // The contract must be renewed with the Arkade server within this period\n  renew = 1008;\n  \n  // Exit timelock: 24 hours (144 blocks)\n  // Time required to exit unilaterally without server involvement\n  exit = 144;\n}\n\ncontract HTLC(\n  pubkey sender,\n  pubkey receiver,\n  bytes hash,\n  int refundTime\n) {\n  // Cooperative close path\n  function together(signature senderSig, signature receiverSig) {\n    require(checkMultisig([sender, receiver]));\n  }\n  \n  // Refund path\n  // This will automatically be compiled into:\n  // 1. Cooperative path: checkSig(sender) && after refundTime && checkSig(server)\n  // 2. Exit path: checkSig(sender) && after refundTime && after 24 hours\n  function refund(signature senderSig) {\n    require(checkSig(senderSig, sender));\n    require(tx.time >= refundTime);\n  }\n  \n  // Claim path\n  // This will automatically be compiled into:\n  // 1. Cooperative path: checkSig(receiver) && sha256(preimage) == hash && checkSig(server)\n  // 2. Exit path: checkSig(receiver) && sha256(preimage) == hash && after 24 hours\n  function claim(signature receiverSig, bytes preimage) {\n    require(checkSig(receiverSig, receiver));\n    require(sha256(preimage) == hash);\n  }\n} ";

export const threshold_oracle = "// Threshold Oracle Contract\n// Generic threshold signature verifier for multi-oracle attestations.\n//\n// This contract demonstrates:\n// - Array types in constructor params (pubkey[] oracles)\n// - Array types in function params (signature[] oracleSigs)\n// - Array indexing (oracles[i])\n// - Loop unrolling with array iteration\n// - Threshold counting for quorum verification\n//\n// N oracles, require M valid signatures over a message.\n\noptions {\n  server = server;\n  exit = 288;\n}\n\ncontract ThresholdOracle(\n  bytes32 tokenAssetId,\n  bytes32 ctrlAssetId,\n  pubkey[] oracles,\n  int threshold\n) {\n  function attest(\n    int amount,\n    bytes32 messageHash,\n    pubkey recipientPk,\n    signature[] oracleSigs\n  ) {\n    require(amount > 0, \"zero\");\n\n    int valid = 0;\n    for (i, sig) in oracleSigs {\n      if (checkSigFromStack(sig, oracles[i], messageHash)) {\n        valid = valid + 1;\n      }\n    }\n    require(valid >= threshold, \"quorum failed\");\n\n    require(tx.inputs[0].assets.lookup(ctrlAssetId) > 0, \"no ctrl\");\n    require(tx.outputs[1].assets.lookup(tokenAssetId) >= amount, \"short\");\n    require(tx.outputs[1].scriptPubKey == new SingleSig(recipientPk), \"wrong dest\");\n    require(tx.outputs[0].scriptPubKey == new ThresholdOracle(tokenAssetId, ctrlAssetId, oracles, threshold), \"broken\");\n  }\n}\n";

export const token_vault = "// Token Vault Contract\n// Demonstrates asset lookup primitives for Arkades Assets\n//\n// This contract locks tokens and allows:\n// 1. deposit() - Owner deposits tokens; output must hold at least as many as input\n// 2. withdraw() - Owner withdraws tokens with server co-signature\n//\n// Asset lookups use the OP_INSPECTINASSETLOOKUP / OP_INSPECTOUTASSETLOOKUP\n// opcodes with sentinel-guard patterns for safe balance verification.\n\noptions {\n  server = server;\n  exit = 144;\n}\n\ncontract TokenVault(\n  pubkey ownerPk,\n  bytes32 tokenAssetId,\n  bytes32 ctrlAssetId\n) {\n  // Deposit: ensure the control asset stays in the output\n  // and output token balance >= input token balance\n  function deposit(signature ownerSig) {\n    // Control asset must be present in input 0\n    require(tx.inputs[0].assets.lookup(ctrlAssetId) > 0, \"no ctrl in input\");\n\n    // Control asset must be present in output 0\n    require(tx.outputs[0].assets.lookup(ctrlAssetId) > 0, \"no ctrl in output\");\n\n    // Output tokens >= input tokens (no leaking tokens)\n    require(\n      tx.outputs[0].assets.lookup(tokenAssetId) >=\n        tx.inputs[0].assets.lookup(tokenAssetId),\n      \"token balance decreased\"\n    );\n\n    // Owner must sign\n    require(checkSig(ownerSig, ownerPk), \"invalid owner signature\");\n  }\n\n  // Withdraw: owner withdraws tokens cooperatively with server\n  function withdraw(signature ownerSig, int amount) {\n    // Control asset must stay in the output\n    require(tx.outputs[0].assets.lookup(ctrlAssetId) > 0, \"no ctrl in output\");\n\n    // Owner must sign\n    require(checkSig(ownerSig, ownerPk), \"invalid owner signature\");\n  }\n}\n";

